   107→  /**
   108→   * Load a layer from disk (model/XX_layername/*.yaml files)
   109→   */
   110→  async loadLayer(name: string): Promise<void> {
   111→    const layerSpan = isTelemetryEnabled
   112→      ? startSpan("layer.load", {
   113→          "layer.name": name,
   114→        })
   115→      : null;
   116→
   117→    try {
   118→      const fs = await import("fs/promises");
   119→      const yaml = await import("yaml");
   120→
   121→      let layerPath: string | null = null;
   122→
   123→      // Auto-discover by scanning directory with naming convention
   124→      const modelDir = `${this.rootPath}/documentation-robotics/model`;
   125→
   126→      try {
   127→        const entries = await fs.readdir(modelDir, { withFileTypes: true });
   128→        const layerDir = entries.find(
   129→          (e) =>
   130→            e.isDirectory() && e.name.match(/^\d{2}_/) && e.name.replace(/^\d{2}_/, "") === name
   131→        );
   132→
   133→        if (layerDir) {
   134→          layerPath = `${modelDir}/${layerDir.name}`;
   135→        }
   136→      } catch {
   137→        // Model directory doesn't exist or can't be read
   138→      }
   139→
   140→      if (!layerPath) {
   141→        return; // Layer directory not found
   142→      }
   143→
   144→      const layer = new Layer(name, this.graph);
   145→      let parseErrorCount = 0;
   146→
   147→      // Load all YAML files in the layer directory
   148→      const files = await fs.readdir(layerPath);
   149→      for (const file of files) {
   150→        if (file.endsWith(".yaml") || file.endsWith(".yml")) {
   151→          const filePath = `${layerPath}/${file}`;
   152→          try {
   153→            const yamlContent = await fs.readFile(filePath, "utf-8");
   154→            const elements = yaml.parse(yamlContent);
   155→
   156→            // Add each element from the YAML file
   157→            if (elements && typeof elements === "object") {
   158→              for (const [key, element] of Object.entries(elements)) {
   159→                if (element && typeof element === "object") {
   160→                  const el: any = element;
   161→
   162→                  let elementUUID = el.id;
   163→                  let extractedType: string | undefined = undefined;
   164→
   165→                  // Legacy format detection:
   166→                  // 1. Dot-separated semantic IDs (e.g., "motivation.goal.test-goal") with 2+ dots
   167→                  // 2. Hyphen-separated legacy format (e.g., "motivation-goal-test-goal")
   168→                  if (typeof elementUUID === "string") {
   169→                    const dotCount = (elementUUID.match(/\./g) || []).length;
   170→                    const isSemanticId = dotCount >= 2;
   171→                    const isLegacyHyphenFormat =
   172→                      !isSemanticId && // Not a semantic ID
   173→                      elementUUID.includes("-") && // Has hyphens
   174→                      elementUUID.startsWith(name) && // Starts with layer name
   175→                      elementUUID.length > name.length + 1; // Has more than just layer name
   176→
   177→                    if (isSemanticId || isLegacyHyphenFormat) {
   178→                      // Extract type from semantic ID format: "layer.type.kebab-case-name"
   179→                      // or legacy format: "layer-type-kebab-case-name"
   180→                      const parts = elementUUID.split(/[.-]/);
   181→                      if (parts.length >= 3) {
   182→                        // Skip first part (layer name), get second part (type)
   183→                        extractedType = parts[1];
   184→                      } else if (parts.length === 2) {
   185→                        // Fallback for simple format
   186→                        extractedType = parts[1];
   187→                      }
   188→
   189→                      // Generate a UUID for the element
   190→                      elementUUID = crypto.randomUUID();
   191→                    }
   192→                  }
   193→
   194→                  const elementName = el.name || key;
   195→                  const elementType = el.type || extractedType;
   196→                  const layerId = el.layer_id || name;
   197→
   198→                  const newElement = new Element({
   199→                    id: elementUUID,
   200→                    spec_node_id: el.spec_node_id,
   201→                    layer_id: layerId,
   202→                    attributes: el.attributes,
   203→                    source_reference: el.source_reference,
   204→                    metadata: el.metadata,
   205→                    name: elementName,
   206→                    type: elementType,
   207→                    description: el.description || "",
   208→                    relationships: el.relationships || [],
   209→                    references: el.references || [],
   210→                    layer: layerId,
   211→                  });
   212→                  layer.addElement(newElement);
   213→                }
   214→              }
   215→            }
   216→          } catch (fileError) {
   217→            // Log YAML parsing errors but continue loading other files
   218→            const errorMsg = fileError instanceof Error ? fileError.message : String(fileError);
   219→            console.error(`Warning: Failed to parse ${filePath}: ${errorMsg}`);
   220→            parseErrorCount++;
   221→            // Continue with next file
   222→          }
   223→        }
   224→      }
   225→
   226→      // If we had parse errors, add a note to the layer
   227→      if (parseErrorCount > 0) {
   228→        console.error(
   229→          `Warning: Layer '${name}' loaded with ${parseErrorCount} YAML parse error(s)`
   230→        );
   231→      }
   232→
   233→      this.layers.set(name, layer);
   234→      this.loadedLayers.add(name);
   235→
   236→      if (isTelemetryEnabled && layerSpan) {
   237→        layerSpan.setAttribute("layer.element_count", layer.elements.size);
   238→      }
   239→    } finally {
   240→      if (isTelemetryEnabled) {
   241→        endSpan(layerSpan);
   242→      }
   243→    }
   244→  }
