   272→  /**
   273→   * Save a layer to disk (model/XX_layername/*.yaml)
   274→   */
   275→  async saveLayer(name: string): Promise<void> {
   276→    const layer = this.layers.get(name);
   277→    if (!layer) {
   278→      throw new Error(`Layer ${name} not found`);
   279→    }
   280→
   281→    const fs = await import("fs/promises");
   282→    const yaml = await import("yaml");
   283→
   284→    let layerPath: string | null = null;
   285→
   286→    // Discover by scanning directory
   287→    const modelDir = `${this.rootPath}/documentation-robotics/model`;
   288→
   289→    try {
   290→      const entries = await fs.readdir(modelDir, { withFileTypes: true });
   291→      const layerDir = entries.find(
   292→        (e) =>
   293→          e.isDirectory() && e.name.match(/^\d{2}_/) && e.name.replace(/^\d{2}_/, "") === name
   294→      );
   295→
   296→      if (layerDir) {
   297→        layerPath = `${modelDir}/${layerDir.name}`;
   298→      }
   299→    } catch {
   300→      // Model directory doesn't exist or can't be read
   301→    }
   302→
   303→    // If still not found, create using default format
   304→    if (!layerPath) {
   305→      // Find the order number for this layer
   306→      // Handle layer names with or without numeric prefix (e.g., "motivation" or "01-motivation")
   307→      const layerNameWithoutPrefix = name.replace(/^\d{2}-/, "");
   308→      const index = CANONICAL_LAYER_NAMES.indexOf(layerNameWithoutPrefix as typeof CANONICAL_LAYER_NAMES[number]);
   309→      if (index >= 0) {
   310→        const orderNum = String(index + 1).padStart(2, "0");
   311→        layerPath = `${this.rootPath}/documentation-robotics/model/${orderNum}_${layerNameWithoutPrefix}`;
   312→        await ensureDir(layerPath);
   313→      } else {
   314→        throw new Error(`Unknown layer ${name} and no path configured in manifest`);
   315→      }
   316→    }
   317→
   318→    // Delete all existing YAML files in the layer directory to ensure
   319→    // we don't keep stale files after element deletion
   320→    try {
   321→      const existingFiles = await fs.readdir(layerPath);
   322→      for (const file of existingFiles) {
   323→        if (file.endsWith(".yaml") || file.endsWith(".yml")) {
   324→          await fs.unlink(`${layerPath}/${file}`);
   325→        }
   326→      }
   327→    } catch (err) {
   328→      // Only ignore "directory not found" errors — re-throw permission/I/O errors
   329→      const isNotFoundError = (err as any)?.code === "ENOENT";
   330→      if (!isNotFoundError) {
   331→        throw new Error(
   332→          `Failed to clean existing YAML files: ${err instanceof Error ? err.message : String(err)}`
   333→        );
   334→      }
   335→    }
   336→
   337→    // Group elements by type, computing the snake_case file stem from the spec node title
   338→    const elementsByType = new Map<string, { stem: string; elements: Element[] }>();
   339→    for (const element of layer.elements.values()) {
   340→      const typeKey = element.type;
   341→      if (!elementsByType.has(typeKey)) {
   342→        const stem = typeToSnakeStem(element.spec_node_id, element.type);
   343→        elementsByType.set(typeKey, { stem, elements: [] });
   344→      }
   345→      elementsByType.get(typeKey)!.elements.push(element);
   346→    }
   347→
   348→    // Internal graph fields — never written to YAML
   349→    const INTERNAL_FIELDS = new Set([
   350→      "__references__", "__relationships__",
   351→      "source", "x-source-reference",
   352→    ]);
   353→
   354→    // Write each type to its own YAML file
   355→    for (const [, { stem, elements }] of elementsByType) {
   356→      const filename = `${stem}.yaml`;
   357→      const filePath = `${layerPath}/${filename}`;
   358→
   359→      // Convert elements to spec-node format YAML
   360→      const yamlData: any = {};
   361→      for (const element of elements) {
   362→        const json = element.toJSON();
   363→
   364→        // Clean attributes: remove graph-internal keys that should not be persisted
   365→        const cleanAttrs = json.attributes
   366→          ? Object.fromEntries(
   367→              Object.entries(json.attributes).filter(([k]) => !INTERNAL_FIELDS.has(k))
   368→            )
   369→          : undefined;
   370→
   371→        // Use UUID as YAML key
   372→        const key = element.id;
   373→        yamlData[key] = {
   374→          id: json.id,
   375→          spec_node_id: json.spec_node_id,
   376→          type: json.type,
   377→          layer_id: json.layer_id,
   378→          name: json.name,
   379→          ...(json.description && { description: json.description }),
   380→          ...(cleanAttrs && Object.keys(cleanAttrs).length > 0 && { attributes: cleanAttrs }),
   381→          ...(json.source_reference && { source_reference: json.source_reference }),
   382→          ...(json.metadata && { metadata: json.metadata }),
   383→          ...(json.references && json.references.length > 0 && { references: json.references }),
   384→          // Relationships are now stored in centralized relationships.yaml, not inline
   385→        };
   386→      }
   387→
   388→      await writeFile(filePath, yaml.stringify(yamlData));
   389→    }
   390→
   391→    layer.markClean();
   392→  }
