   497→  private getLayerElementCounts(layer: Layer): Record<string, number> {
   498→    const counts: Record<string, number> = {};
   499→    for (const element of layer.elements.values()) {
   500→      counts[element.type] = (counts[element.type] || 0) + 1;
   501→    }
   502→    return counts;
   503→  }
