   522→          const edge: GraphEdge = {
   523→            id: `rel-${i}-${crypto.randomBytes(4).toString("hex")}`,
   524→            source: rel.source,
   525→            destination: rel.target,
   526→            predicate: rel.predicate,
   527→            properties: rel.properties,
   528→            category: rel.category,
   529→          };
   530→          this.graph.addEdge(edge);
   531→        }
   532→      }
   533→    } catch (err) {
   534→      // If file doesn't exist, that's okay - start with empty relationships
   535→      if ((err as any).code !== "ENOENT") {
   536→        // But if it's a different error, we should know about it
   537→        if (process.env.DEBUG) {
   538→          console.debug(`Warning: Failed to load relationships.yaml: ${err}`);
   539→        }
   540→      }
   541→    }
   542→  }
