   874→  /**
   875→   * Save dirty layers with atomic write semantics
   876→   * Writes to temporary file first, then renames on success to ensure data safety
   877→   *
   878→   * @throws Error if atomic write fails
   879→   */
   880→  async saveDirtyLayersAtomic(): Promise<void> {
   881→    // First, save all layers to temporary files
   882→    const tempLayerWrites: Array<{ layer: Layer; tempPath: string }> = [];
   883→
   884→    try {
   885→      for (const layer of this.layers.values()) {
   886→        if (layer.isDirty()) {
   887→          const layerPath = path.join(
   888→            this.rootPath,
   889→            "documentation-robotics",
   890→            "model",
   891→            `${layer.name}_layer`
   892→          );
   893→
   894→          const tempPath = `${layerPath}.tmp`;
   895→          await ensureDir(tempPath);
   896→
   897→          // Write layer elements to temp directory
   898→          for (const element of layer.elements.values()) {
   899→            const elementPath = path.join(tempPath, `${element.id}.json`);
   900→            const content = JSON.stringify(element.toJSON(), null, 2);
   901→            await writeFile(elementPath, content);
   902→          }
   903→
   904→          tempLayerWrites.push({ layer, tempPath });
   905→        }
   906→      }
   907→
   908→      // All temp writes succeeded, now commit by renaming
   909→      for (const { layer, tempPath } of tempLayerWrites) {
   910→        const layerPath = path.join(
   911→          this.rootPath,
   912→          "documentation-robotics",
   913→          "model",
   914→          `${layer.name}_layer`
   915→        );
   916→
   917→        // Remove old directory and rename temp to actual
   918→        if (await this.directoryExists(layerPath)) {
   919→          await fs.rm(layerPath, { recursive: true, force: true });
   920→        }
   921→        await fs.rename(tempPath, layerPath);
   922→      }
   923→    } catch (error) {
   924→      // Cleanup any temp directories on failure
   925→      for (const { tempPath } of tempLayerWrites) {
   926→        if (await this.directoryExists(tempPath)) {
   927→          await fs.rm(tempPath, { recursive: true, force: true });
   928→        }
   929→      }
   930→      throw error;
   931→    }
   932→  }
   933→
   934→  /**
   935→   * Helper: Check if file exists
   936→   */
   937→  private async fileExists(filePath: string): Promise<boolean> {
   938→    try {
   939→      await fs.access(filePath);
   940→      return true;
   941→    } catch {
   942→      return false;
   943→    }
   944→  }
   945→
   946→  /**
   947→   * Helper: Check if directory exists
   948→   */
   949→  private async directoryExists(dirPath: string): Promise<boolean> {
   950→    try {
   951→      const stat = await fs.stat(dirPath);
   952→      return stat.isDirectory();
   953→    } catch {
   954→      return false;
   955→    }
   956→  }
   957→
   958→  /**
   959→   * Helper: Recursively copy directory
   960→   */
   961→  private async copyDirectory(src: string, dest: string): Promise<void> {
   962→    await ensureDir(dest);
   963→    const entries = await fs.readdir(src, { withFileTypes: true });
   964→
   965→    for (const entry of entries) {
   966→      const srcPath = path.join(src, entry.name);
   967→      const destPath = path.join(dest, entry.name);
   968→
   969→      if (entry.isDirectory()) {
   970→        await this.copyDirectory(srcPath, destPath);
   971→      } else {
   972→        await fs.copyFile(srcPath, destPath);
   973→      }
   974→    }
   975→  }
   976→}
