     1→/**
     2→ * Show detailed information about an element
     3→ */
     4→
     5→import ansis from "ansis";
     6→import { Model } from "../core/model.js";
     7→import { findElementLayer } from "../utils/element-utils.js";
     8→import { CLIError, ErrorCategory, handleError } from "../utils/errors.js";
     9→import { isTelemetryEnabled, startSpan, endSpan } from "../telemetry/index.js";
    10→import { getErrorMessage } from "../utils/errors.js";
    11→
    12→export async function showCommand(id: string, options: { model?: string } = {}): Promise<void> {
    13→  const span = isTelemetryEnabled
    14→    ? startSpan("show.execute", {
    15→        "show.elementId": id,
    16→      })
    17→    : null;
    18→
    19→  try {
    20→    // Load model (optionally from specified path)
    21→    const model = await Model.load(options.model);
    22→
    23→    // Find element
    24→    const layerName = await findElementLayer(model, id);
    25→    if (!layerName) {
    26→      if (isTelemetryEnabled && span) {
    27→        (span as any).setAttribute("show.found", false);
    28→      }
    29→      throw new CLIError(`Element ${id} not found`, ErrorCategory.USER, [
    30→        `Use "dr search ${id}" to find similar elements`,
    31→        'Use "dr list <layer>" to list all elements in a layer',
    32→      ]);
    33→    }
    34→
    35→    const layer = await model.getLayer(layerName);
    36→    if (!layer) {
    37→      throw new CLIError(`Layer ${layerName} not found`, ErrorCategory.USER, [
    38→        'Use "dr schema layers" to list all available layers',
    39→      ]);
    40→    }
    41→
    42→    const element = layer.getElement(id);
    43→    if (!element) {
    44→      throw new CLIError(`Element ${id} not found`, ErrorCategory.USER, [
    45→        `Use "dr search ${id}" to find similar elements`,
    46→        'Use "dr list <layer>" to list all elements in a layer',
    47→      ]);
    48→    }
    49→
    50→    if (isTelemetryEnabled && span) {
    51→      (span as any).setAttribute("show.found", true);
    52→      (span as any).setAttribute("show.layer", layerName);
    53→      (span as any).setAttribute("show.type", element.type);
    54→      (span as any).setAttribute(
    55→        "show.hasReferences",
    56→        element.references && element.references.length > 0
    57→      );
    58→      (span as any).setAttribute(
    59→        "show.hasRelationships",
    60→        element.relationships && element.relationships.length > 0
    61→      );
    62→    }
    63→
    64→    // Display element information
    65→    console.log("");
    66→    console.log(ansis.bold(`${ansis.blue("Element:")} ${id}`));
    67→    console.log(ansis.dim("─".repeat(60)));
    68→    console.log(`${ansis.gray("Layer:")}       ${layerName}`);
    69→    console.log(`${ansis.gray("Type:")}        ${element.type}`);
    70→    console.log(`${ansis.gray("Name:")}        ${element.name}`);
    71→
    72→    if (element.description) {
    73→      console.log(`${ansis.gray("Description:")} ${element.description}`);
    74→    }
    75→
    76→    // Display properties (attributes)
    77→    if (Object.keys(element.attributes).length > 0) {
    78→      console.log("");
    79→      console.log(ansis.bold("Properties:"));
    80→      for (const [key, value] of Object.entries(element.attributes)) {
    81→        const displayValue = typeof value === "string" ? value : JSON.stringify(value, null, 2);
    82→        console.log(`  ${ansis.cyan(key)}: ${displayValue}`);
    83→      }
    84→    }
    85→
    86→    // Display references
    87→    if (element.references && element.references.length > 0) {
    88→      console.log("");
    89→      console.log(ansis.bold("References:"));
    90→      for (const ref of element.references) {
    91→        console.log(`  → ${ansis.yellow(ref.target)} (${ref.type})`);
    92→        if (ref.description) {
    93→          console.log(`    ${ansis.dim(ref.description)}`);
    94→        }
    95→      }
    96→    }
    97→
    98→    // Display relationships
    99→    if (element.relationships && element.relationships.length > 0) {
   100→      console.log("");
   101→      console.log(ansis.bold("Relationships:"));
   102→      for (const rel of element.relationships) {
   103→        console.log(`  ${ansis.magenta(rel.predicate)}: ${rel.target}`);
   104→        if (rel.properties) {
   105→          const propStr = Object.entries(rel.properties)
   106→            .map(([k, v]) => `${k}=${v}`)
   107→            .join(", ");
   108→          console.log(`    ${ansis.dim(propStr)}`);
   109→        }
   110→      }
   111→    }
   112→
   113→    // Display source code location if present
   114→    const sourceRef = element.getSourceReference();
   115→    if (sourceRef) {
   116→      console.log("");
   117→      console.log(ansis.bold("Source Code Location:"));
   118→      console.log(`  ${ansis.gray("Provenance:")} ${sourceRef.provenance}`);
   119→
   120→      sourceRef.locations.forEach((loc, idx) => {
   121→        console.log(`  ${ansis.gray("Location " + (idx + 1) + ":")}`);
   122→        console.log(`    File: ${ansis.cyan(loc.file)}`);
   123→        if (loc.symbol) {
   124→          console.log(`    Symbol: ${ansis.cyan(loc.symbol)}`);
   125→        }
   126→      });
   127→
   128→      if (sourceRef.repository) {
   129→        console.log(`  ${ansis.gray("Repository Context:")}`);
   130→        if (sourceRef.repository.url) {
   131→          console.log(`    Remote: ${ansis.cyan(sourceRef.repository.url)}`);
   132→        }
   133→        if (sourceRef.repository.commit) {
   134→          console.log(`    Commit: ${ansis.cyan(sourceRef.repository.commit)}`);
   135→        }
   136→      }
   137→    }
   138→
   139→    console.log("");
   140→
   141→    if (isTelemetryEnabled && span) {
   142→      (span as any).setStatus({ code: 0 });
   143→    }
   144→  } catch (error) {
   145→    if (isTelemetryEnabled && span) {
   146→      (span as any).recordException(error as Error);
   147→      (span as any).setStatus({
   148→        code: 2,
   149→        message: getErrorMessage(error),
   150→      });
   151→    }
   152→    handleError(error);
   153→  } finally {
   154→    endSpan(span);
   155→  }
   156→}
   157→

