     4→
     5→import { Model } from "../core/model.js";
     6→
     7→/**
     8→ * Find which layer contains an element by ID
     9→ */
    10→export async function findElementLayer(
    11→  model: Model,
    12→  elementId: string
    13→): Promise<string | undefined> {
    14→  for (const layerName of model.getLayerNames()) {
    15→    const layer = await model.getLayer(layerName);
    16→    if (layer && layer.getElement(elementId)) {
    17→      return layerName;
    18→    }
    19→  }
    20→  return undefined;
    21→}
