      // Add some test elements
      await runDr("element", "add", "motivation", "goal", "Goal One");
      await runDr("element", "add", "motivation", "goal", "Goal Two");
      await runDr("element", "add", "motivation", "stakeholder", "Stakeholder One");
    });

