    const layer = new Layer("motivation");

    expect(layer.isDirty()).toBe(false);

    layer.addElement(
      new Element({
        id: "motivation-goal-test",
        type: "Goal",
        name: "Test Goal",
      })
    );

    expect(layer.isDirty()).toBe(true);

    layer.markClean();

    expect(layer.isDirty()).toBe(false);
  });

  it("should serialize to JSON", () => {
    const element = new Element({
      id: "motivation-goal-test",
      type: "Goal",
      name: "Test Goal",
      description: "A test goal",
    });

