     5→/**
     6→ * Layer class - thin wrapper over graph model for backward compatibility
     7→ * Queries the graph for elements in a specific layer
     8→ */
     9→export class Layer {
    10→  name: string;
    11→  graph: GraphModel;
    12→  metadata?: { layer: string; version: string };
    13→  private dirty: boolean = false;
    14→  private cachedElements: Map<string, Element> | null = null;
    15→  private cachedNodesVersion: number = 0;
    16→
    17→  constructor(
    18→    name: string,
    19→    elementsOrGraph?: Element[] | GraphModel,
    20→    elementsIfGraphPassed?: Element[]
    21→  ) {
    22→    this.name = name;
    23→
    24→    // Handle overloaded constructor:
    25→    // new Layer(name) - create with empty graph
    26→    // new Layer(name, elements) - create with elements array
    27→    // new Layer(name, graph) - create with provided graph
    28→    // new Layer(name, undefined, elements) - create with elements
    29→    // new Layer(name, graph, elements) - create with provided graph and elements
    30→    let actualGraph: GraphModel | undefined;
    31→    let elementsToAdd: Element[] = [];
    32→
    33→    if (elementsOrGraph instanceof GraphModel) {
    34→      // Called with graph as second parameter
    35→      actualGraph = elementsOrGraph;
    36→      // Elements are in the third parameter if provided
    37→      if (Array.isArray(elementsIfGraphPassed)) {
    38→        elementsToAdd = elementsIfGraphPassed;
    39→      }
    40→    } else if (Array.isArray(elementsOrGraph)) {
    41→      // Called with elements as second parameter
    42→      elementsToAdd = elementsOrGraph;
    43→    } else if (elementsOrGraph === undefined && Array.isArray(elementsIfGraphPassed)) {
    44→      // Called with undefined graph and elements in third parameter
    45→      elementsToAdd = elementsIfGraphPassed;
    46→    }
    47→
    48→    // Use provided graph or create a new one
    49→    this.graph = actualGraph || new GraphModel();
    50→
    51→    // Add elements to the graph (without marking as dirty during construction)
    52→    for (const element of elementsToAdd) {
    53→      // Ensure element has the correct layer
    54→      element.layer = this.name;
    55→      // Also set layer_id to maintain consistency with layer name
    56→      if (!element.layer_id || element.layer_id === "") {
    57→        element.layer_id = this.name;
    58→      }
    59→      const node = GraphModel.fromElement(element);
    60→
    61→      // Store references and relationships as node properties for preservation
    62→      if (element.references && element.references.length > 0) {
    63→        node.properties["__references__"] = element.references;
    64→      }
    65→      if (element.relationships && element.relationships.length > 0) {
    66→        node.properties["__relationships__"] = element.relationships;
    67→      }
    68→
    69→      this.graph.addNode(node);
    70→      // Don't mark as dirty during construction - elements added in constructor are initial state
    71→    }
    72→  }
    73→
    74→  /**
    75→   * Get all elements in this layer from the graph
    76→   * Converts graph nodes back to Elements for backward compatibility
    77→   * Results are cached and invalidated when the underlying graph changes
    78→   */
    79→  get elements(): Map<string, Element> {
    80→    const currentVersion = this.graph.getNodesVersion();
    81→
    82→    // Return cached result if graph hasn't changed
    83→    if (this.cachedElements !== null && this.cachedNodesVersion === currentVersion) {
    84→      return this.cachedElements;
    85→    }
    86→
    87→    // Rebuild cache
    88→    const result = new Map<string, Element>();
    89→    const nodes = this.graph.getNodesByLayer(this.name);
    90→
    91→    for (const node of nodes) {
    92→      const element = new Element({
    93→        id: node.id,
    94→        spec_node_id: node.spec_node_id,
    95→        layer_id: node.layer_id,
    96→        type: node.type,
    97→        name: node.name,
    98→        description: node.description,
    99→        attributes: node.attributes,
   100→        source_reference: node.source_reference,
   101→        metadata: node.metadata,
   102→        layer: node.layer,
   103→        references: (node.properties["__references__"] ?? []) as Reference[],
   104→        relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   105→      });
   106→      result.set(node.id, element);
   107→    }
   108→
   109→    this.cachedElements = result;
   110→    this.cachedNodesVersion = currentVersion;
   111→    return result;
   112→  }
   113→
   114→  /**
   115→   * Add an element to the layer (stores in graph)
   116→   */
   117→  addElement(element: Element): void {
   118→    // Ensure element has the correct layer
   119→    element.layer = this.name;
   120→    // Also set layer_id to maintain consistency with layer name
   121→    if (!element.layer_id || element.layer_id === "") {
   122→      element.layer_id = this.name;
   123→    }
   124→    const node = GraphModel.fromElement(element);
   125→
   126→    // Store references and relationships as node properties for preservation
   127→    if (element.references && element.references.length > 0) {
   128→      node.properties["__references__"] = element.references;
   129→    }
   130→    if (element.relationships && element.relationships.length > 0) {
   131→      node.properties["__relationships__"] = element.relationships;
   132→    }
   133→
   134→    // Add node to graph first
   135→    this.graph.addNode(node);
   136→
   137→    // Create graph edges from references for export compatibility
   138→    // Only create edges if both source and destination nodes exist
   139→    if (element.references && element.references.length > 0) {
   140→      for (const ref of element.references) {
   141→        if (this.graph.nodes.has(ref.source) && this.graph.nodes.has(ref.target)) {
   142→          this.graph.addEdge({
   143→            id: `${ref.source}-${ref.type}-${ref.target}`,
   144→            source: ref.source,
   145→            destination: ref.target,
   146→            predicate: ref.type,
   147→            properties: {},
   148→          });
   149→        }
   150→      }
   151→    }
   152→
   153→    // Create graph edges from relationships for export compatibility
   154→    // Only create edges if both source and destination nodes exist
   155→    if (element.relationships && element.relationships.length > 0) {
   156→      for (const rel of element.relationships) {
   157→        if (this.graph.nodes.has(rel.source) && this.graph.nodes.has(rel.target)) {
   158→          this.graph.addEdge({
   159→            id: `${rel.source}-${rel.predicate}-${rel.target}`,
   160→            source: rel.source,
   161→            destination: rel.target,
   162→            predicate: rel.predicate,
   163→            properties: {},
   164→          });
   165→        }
   166→      }
   167→    }
   168→
   169→    this.dirty = true;
   170→  }
