   172→  /**
   173→   * Get an element by UUID from the graph.
   174→   * Only direct UUID lookup is supported; semantic ID lookup has been removed.
   175→   *
   176→   * @param id - UUID of the element to get
   177→   * @returns The element if found, undefined if not found
   178→   */
   179→  getElement(id: string): Element | undefined {
   180→    const node = this.graph.nodes.get(id);
   181→
   182→    if (!node || node.layer !== this.name) {
   183→      return undefined;
   184→    }
   185→
   186→    return new Element({
   187→      id: node.id,
   188→      spec_node_id: node.spec_node_id,
   189→      layer_id: node.layer_id,
   190→      type: node.type,
   191→      name: node.name,
   192→      description: node.description,
   193→      attributes: node.attributes,
   194→      source_reference: node.source_reference,
   195→      metadata: node.metadata,
   196→      layer: node.layer,
   197→      references: (node.properties["__references__"] ?? []) as Reference[],
   198→      relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   199→    });
   200→  }
   201→
   202→  /**
   203→   * Find an element by semantic ID (for testing/compatibility).
   204→   * This is a helper method for finding elements by semantic ID format:
   205→   * - Dot-separated: {layer}.{type}.{kebab-name}
   206→   * - Hyphen-separated legacy: {layer}-{type}-{kebab-name}
   207→   *
   208→   * @param semanticId - Semantic ID of the element to find
   209→   * @returns The element if found, undefined if not found
   210→   */
   211→  findBySemanticId(semanticId: string): Element | undefined {
   212→    const dotCount = (semanticId.match(/\./g) || []).length;
   213→    const isDotSeparated = dotCount >= 2;
   214→    const isHyphenSeparated = semanticId.includes("-") && semanticId.startsWith(this.name) && semanticId.length > this.name.length + 1;
   215→
   216→    if (!isDotSeparated && !isHyphenSeparated) {
   217→      return undefined;
   218→    }
   219→
   220→    // Search all nodes in the layer
   221→    for (const candidate of this.graph.nodes.values()) {
   222→      if (candidate.layer !== this.name) {
   223→        continue;
   224→      }
   225→
   226→      // Build semantic IDs from element name
   227→      const kebabName = candidate.name
   228→        .replace(/[\s_]+/g, "-")
   229→        .replace(/([a-z])([A-Z])/g, "$1-$2")
   230→        .toLowerCase()
   231→        .replace(/-+/g, "-")
   232→        .replace(/^-+|-+$/g, "");
   233→
   234→      const semanticIds = [
   235→        `${candidate.layer_id || this.name}.${candidate.type}.${kebabName}`,
   236→        `${candidate.layer_id || this.name}-${candidate.type}-${kebabName}`,
   237→      ];
   238→
   239→      if (semanticIds.includes(semanticId)) {
   240→        return new Element({
   241→          id: candidate.id,
   242→          spec_node_id: candidate.spec_node_id,
   243→          layer_id: candidate.layer_id,
   244→          type: candidate.type,
   245→          name: candidate.name,
   246→          description: candidate.description,
   247→          attributes: candidate.attributes,
   248→          source_reference: candidate.source_reference,
   249→          metadata: candidate.metadata,
   250→          layer: candidate.layer,
   251→          references: (candidate.properties["__references__"] ?? []) as Reference[],
   252→          relationships: (candidate.properties["__relationships__"] ?? []) as Relationship[],
   253→        });
   254→      }
   255→    }
   256→
   257→    return undefined;
   258→  }
