   184→/**
   185→ * SHA256 hash branded type for compile-time safety
   186→ * Prevents accidental misuse of arbitrary strings as cryptographic checksums
   187→ */
   188→export type Sha256Hash = string & { readonly __brand: "Sha256Hash" };
   189→
   190→/**
   191→ * Create a Sha256Hash from a hex string
   192→ * This is the only valid way to construct a Sha256Hash value
   193→ *
   194→ * @param hash - The hex string representation of a SHA256 hash
   195→ * @returns A branded Sha256Hash type
   196→ * @throws Error if the hash is not a valid 64-character hex string
   197→ */
   198→export function createSha256Hash(hash: string): Sha256Hash {
   199→  if (!/^[a-f0-9]{64}$/.test(hash)) {
   200→    throw new Error(`Invalid SHA256 hash format. Expected 64-character hex string, got: ${hash}`);
   201→  }
   202→  return hash as Sha256Hash;
   203→}
   204→
   205→/**
   206→ * Backup manifest entry for a single file
   207→ * All properties are readonly to enforce immutability of backup records
   208→ */
   209→export interface BackupManifestFile {
   210→  readonly path: string; // Relative path to the file in the backup directory
   211→  readonly checksum: Sha256Hash; // SHA256 hash of the file contents (branded type)
   212→  readonly size: number; // File size in bytes
   213→}
   214→
   215→/**
   216→ * Backup manifest tracking files and creation timestamp
   217→ * Used for backup integrity validation and recovery
   218→ * All properties are readonly to enforce immutability of backup records
   219→ */
   220→export interface BackupManifest {
   221→  readonly files: ReadonlyArray<BackupManifestFile>; // Array of backed up files with metadata
   222→  readonly timestamp: string; // ISO 8601 timestamp when backup was created
   223→}
   224→
   225→/**
   226→ * Create and validate a BackupManifest from raw data
   227→ * Validates structure and transforms string checksums to Sha256Hash branded type
   228→ *
   229→ * @param data - Unknown data to validate (typically from JSON parsing)
   230→ * @returns Validated and typed BackupManifest object
   231→ * @throws Error if data doesn't match expected structure or contains invalid checksums
   232→ */
   233→export function createBackupManifest(data: unknown): BackupManifest {
   234→  if (!data || typeof data !== "object") {
   235→    throw new Error("Backup manifest must be an object");
   236→  }
   237→
   238→  const obj = data as Record<string, unknown>;
   239→
   240→  if (!obj.files || !Array.isArray(obj.files)) {
   241→    throw new Error("Backup manifest must have a files array");
   242→  }
   243→
   244→  if (obj.timestamp && typeof obj.timestamp !== "string") {
   245→    throw new Error("Backup manifest timestamp must be a string if provided");
   246→  }
   247→
   248→  // Validate ISO 8601 timestamp if provided
   249→  let timestamp: string;
   250→  if (obj.timestamp) {
   251→    const timestampDate = new Date(obj.timestamp as string);
   252→    if (isNaN(timestampDate.getTime())) {
   253→      throw new Error(`Invalid timestamp format: ${obj.timestamp}. Expected ISO 8601 string.`);
   254→    }
   255→    timestamp = obj.timestamp as string;
   256→  } else {
   257→    timestamp = new Date().toISOString();
   258→  }
   259→
   260→  // Validate and transform each file entry
   261→  const files: readonly BackupManifestFile[] = obj.files.map((file: unknown, index: number) => {
   262→    if (!file || typeof file !== "object") {
   263→      throw new Error(`Backup manifest file entry ${index} must be an object`);
   264→    }
   265→
   266→    const fileObj = file as Record<string, unknown>;
   267→
   268→    if (typeof fileObj.path !== "string" || !fileObj.path) {
   269→      throw new Error(`Backup manifest file entry ${index} must have a non-empty path string`);
   270→    }
   271→
   272→    if (typeof fileObj.checksum !== "string") {
   273→      throw new Error(`Backup manifest file entry ${index} must have a checksum string`);
   274→    }
   275→
   276→    if (typeof fileObj.size !== "number" || fileObj.size < 0) {
   277→      throw new Error(`Backup manifest file entry ${index} must have a non-negative size number`);
   278→    }
   279→
   280→    return {
   281→      path: fileObj.path,
   282→      checksum: createSha256Hash(fileObj.checksum),
   283→      size: fileObj.size,
   284→    };
   285→  });
   286→
   287→  return {
   288→    files,
   289→    timestamp,
   290→  };
   291→}
