   293→/**
   294→ * Verify backup manifest against actual file checksums
   295→ * Checks that all files in the manifest exist and have matching checksums
   296→ *
   297→ * @param manifest - The backup manifest to verify
   298→ * @param readFile - Function to read file contents by path
   299→ * @param fileExists - Function to check if a file exists by path
   300→ * @param backupDir - Base directory path for resolving relative file paths
   301→ * @returns Promise resolving to verification result with detailed error information
   302→ */
   303→export async function verifyBackupIntegrity(
   304→  manifest: BackupManifest,
   305→  readFile: (path: string) => Promise<string>,
   306→  fileExists: (path: string) => Promise<boolean>,
   307→  backupDir: string
   308→): Promise<{
   309→  isValid: boolean;
   310→  filesChecked: number;
   311→  errors: string[];
   312→}> {
   313→  const { createHash } = await import("crypto");
   314→  const path = await import("path");
   315→
   316→  const errors: string[] = [];
   317→  let filesChecked = 0;
   318→
   319→  try {
   320→    // Verify each file in the manifest
   321→    for (const file of manifest.files) {
   322→      filesChecked++;
   323→      const backupFilePath = path.join(backupDir, file.path);
   324→
   325→      // Check file exists
   326→      if (!(await fileExists(backupFilePath))) {
   327→        errors.push(`Missing: ${file.path}`);
   328→        continue;
   329→      }
   330→
   331→      try {
   332→        // Read file and verify checksum
   333→        const content = await readFile(backupFilePath);
   334→        const checksum = createHash("sha256").update(content).digest("hex") as Sha256Hash;
   335→
   336→        if (checksum !== file.checksum) {
   337→          errors.push(
   338→            `Checksum mismatch: ${file.path} (expected ${file.checksum}, got ${checksum})`
   339→          );
   340→          continue;
   341→        }
   342→
   343→        // Verify size matches
   344→        if (content.length !== file.size) {
   345→          errors.push(`Size mismatch: ${file.path} (expected ${file.size}, got ${content.length})`);
   346→        }
   347→      } catch (err) {
   348→        errors.push(
   349→          `Failed to verify: ${file.path} (${err instanceof Error ? err.message : String(err)})`
   350→        );
   351→      }
   352→    }
   353→
   354→    return {
   355→      isValid: errors.length === 0,
   356→      filesChecked,
   357→      errors,
   358→    };
   359→  } catch (err) {
   360→    return {
   361→      isValid: false,
   362→      filesChecked,
   363→      errors: [
   364→        ...errors,
   365→        `Integrity verification failed: ${err instanceof Error ? err.message : String(err)}`,
   366→      ],
   367→    };
   368→  }
   369→}
