     4→ * Changesets group related modifications to the architecture model for:
     5→ * - Staging changes before committing to the base model
     6→ * - Audit trail of model changes with before/after snapshots
     7→ * - Collaboration and change tracking across team members
     8→ *
     9→ * Uses the staging workflow (staged/committed/discarded).
    10→ */
    11→
    12→/**
    13→ * Represents a single change in a changeset.
    14→ * Records element mutations with before/after snapshots for audit purposes.
    15→ */
    16→export interface Change {
    17→  type: "add" | "update" | "delete";
    18→  elementId: string;
    19→  layerName: string;
    20→  before?: Record<string, unknown>; // Element state before change (for update/delete)
    21→  after?: Record<string, unknown>; // Element state after change (for add/update)
    22→  timestamp?: string; // ISO timestamp; optional in interface but always set before storage
    23→}
    24→
