    26→ * Represents a staged change with sequence number for ordered replay.
    27→ * Used in the staging workflow to ensure changes are applied in order during commit.
    28→ */
    29→export interface StagedChange extends Change {
    30→  readonly sequenceNumber: number; // 0-based index for ordering during commit replay
    31→}
