static fromElement(element: Element): GraphNode {
  return {
    id: element.id,
    layer: element.layer || "unknown",
    type: element.type,
    name: element.name,
    description: element.description,
    properties: element.attributes || {},
    spec_node_id: element.spec_node_id || undefined,
    layer_id: element.layer_id || undefined,
    attributes: element.attributes && Object.keys(element.attributes).length > 0
      ? element.attributes
      : undefined,
    source_reference: element.source_reference,
    metadata: element.metadata,
  };
}

/**
 * Convert Relationship to GraphEdge
 */
static relationshipToEdge(relationship: Relationship, edgeId: string): GraphEdge {
  return {
    id: edgeId,
    source: relationship.source,
    destination: relationship.target,
    predicate: relationship.predicate,
    properties: relationship.properties,
  };
}

