     1→/**
     2→ * Relationship subcommands for managing intra-layer relationships
     3→ */
     4→
     5→import { Command } from "commander";
     6→import ansis from "ansis";
     7→import { Model } from "../core/model.js";
     8→import { findElementLayer } from "../utils/element-utils.js";
     9→import { CLIError, ErrorCategory, handleError } from "../utils/errors.js";
    10→import {
    11→  getValidRelationships,
    12→  getValidPredicatesForSource,
    13→  getValidDestinationsForSourceAndPredicate,
    14→} from "../generated/relationship-index.js";
