    16→
    17→/**
    18→ * Validate element properties and construct a SpecNodeId
    19→ * @throws {CLIError} if element properties are invalid
    20→ */
    21→function constructSpecNodeId(
    22→  element: { layer_id?: unknown; type?: unknown },
    23→  elementId: string
    24→): string {
    25→  const layerId = element.layer_id;
    26→  const type = element.type;
    27→
    28→  if (typeof layerId !== "string" || !layerId) {
    29→    throw new CLIError(
    30→      `Invalid element ${elementId}: missing or invalid layer_id`,
    31→      ErrorCategory.SYSTEM
    32→    );
    33→  }
    34→
    35→  if (typeof type !== "string" || !type) {
    36→    throw new CLIError(
    37→      `Invalid element ${elementId}: missing or invalid type`,
    38→      ErrorCategory.SYSTEM
    39→    );
    40→  }
    41→
    42→  // Normalize type name for schema validation (e.g., "process" -> "businessprocess")
    43→  const normalizedType = normalizeNodeType(layerId, type);
    44→
    45→  return `${layerId}.${normalizedType}`;
    46→}
    47→
    48→/**
    49→ * Validate a relationship combination using schema-driven registry
    50→ * @returns {valid, suggestions} where suggestions are provided if invalid
    51→ */
    52→export function validateRelationshipCombination(
    53→  sourceSpecNodeId: string,
    54→  predicate: string,
    55→  destSpecNodeId: string
    56→): { valid: boolean; suggestions?: string[] } {
    57→  const valid =
    58→    getValidRelationships(sourceSpecNodeId, predicate, destSpecNodeId)
    59→      .length > 0;
    60→
    61→  if (valid) {
    62→    return { valid: true };
    63→  }
    64→
    65→  // Generate helpful suggestions
    66→  const suggestions: string[] = [];
    67→  const validPredicates = getValidPredicatesForSource(sourceSpecNodeId);
    68→
    69→  if (validPredicates.length > 0) {
    70→    suggestions.push(
    71→      `Valid predicates for ${sourceSpecNodeId}: ${validPredicates.join(", ")}`
    72→    );
    73→  } else {
    74→    suggestions.push(`No valid relationships defined for ${sourceSpecNodeId}`);
    75→  }
    76→
    77→  // If predicate is provided, show valid destinations
    78→  if (predicate) {
    79→    const validDests = getValidDestinationsForSourceAndPredicate(
    80→      sourceSpecNodeId,
    81→      predicate
    82→    );
    83→    if (validDests.length > 0) {
    84→      suggestions.push(
    85→        `Valid destinations for --[${predicate}]-->: ${validDests.join(", ")}`
    86→      );
    87→    } else {
    88→      suggestions.push(
    89→        `No valid destinations for ${sourceSpecNodeId} --[${predicate}]-->`
    90→      );
    91→    }
    92→  }
    93→
    94→  return { valid: false, suggestions };
    95→}
    96→
    97→/**
    98→ * Get cardinality and strength info for a relationship
    99→ */
   100→export function getRelationshipConstraints(
   101→  sourceSpecNodeId: string,
   102→  predicate: string,
   103→  destSpecNodeId: string
   104→): { cardinality: string; strength: string } | null {
   105→  const rels = getValidRelationships(
   106→    sourceSpecNodeId,
   107→    predicate,
   108→    destSpecNodeId
   109→  );
   110→  if (rels.length === 0) return null;
   111→
   112→  const rel = rels[0];
   113→  return {
   114→    cardinality: rel.cardinality,
   115→    strength: rel.strength,
   116→  };
   117→}
   118→
   119→export function relationshipCommands(program: Command): void {
   120→  program
   121→    .command("add <source> <target>")
   122→    .description("Add a relationship between elements")
   123→    .requiredOption(
   124→      "--predicate <predicate>",
   125→      "Relationship predicate (e.g., depends-on, implements)"
   126→    )
   127→    .option("--properties <json>", "Relationship properties (JSON)")
   128→    .addHelpText(
   129→      "after",
   130→      `
   131→Examples:
   132→  $ dr relationship add business-service-a business-service-b --predicate depends-on
   133→  $ dr relationship add api-endpoint-1 api-endpoint-2 --predicate "service-of"
   134→  $ dr relationship add element-1 element-2 --predicate implements --properties '{"method":"REST"}'`
   135→    )
   136→    .action(async (source, target, options) => {
   137→      try {
   138→        // Load model
   139→        const model = await Model.load();
   140→
   141→        // Find source element
   142→        const sourceLayerName = await findElementLayer(model, source);
   143→        if (!sourceLayerName) {
   144→          throw new CLIError(`Source element ${source} not found`, ErrorCategory.USER);
   145→        }
   146→
   147→        // Find source element for schema validation
   148→        const sourceLayer = await model.getLayer(sourceLayerName);
   149→        if (!sourceLayer) {
   150→          throw new CLIError(`Source element ${source} not found`, ErrorCategory.USER);
   151→        }
   152→        const sourceElement = sourceLayer.getElement(source);
   153→        if (!sourceElement) {
   154→          throw new CLIError(`Source element ${source} not found`, ErrorCategory.USER);
   155→        }
   156→
   157→        // Find target element
   158→        const targetLayerName = await findElementLayer(model, target);
   159→        if (!targetLayerName) {
   160→          throw new CLIError(`Target element ${target} not found`, ErrorCategory.USER);
   161→        }
   162→
   163→        // Find target element for schema validation
   164→        const targetLayer = await model.getLayer(targetLayerName);
   165→        if (!targetLayer) {
   166→          throw new CLIError(`Target element ${target} not found`, ErrorCategory.USER);
   167→        }
   168→        const targetElement = targetLayer.getElement(target);
   169→        if (!targetElement) {
   170→          throw new CLIError(`Target element ${target} not found`, ErrorCategory.USER);
   171→        }
   172→
   173→        // Relationships are intra-layer only
   174→        if (sourceLayerName !== targetLayerName) {
   175→          throw new CLIError(
   176→            "cannot add cross-layer relationship. Relationships must be within the same layer.",
   177→            ErrorCategory.USER
   178→          );
   179→        }
   180→
