    18→
    19→/**
    20→ * Convert a PascalCase title to snake_case.
    21→ * Handles acronyms correctly: "UXApplication" → "ux_application", "OpenAPIDocument" → "open_api_document".
    22→ */
    23→function titleToSnakeCase(title: string): string {
    24→  return title
    25→    .replace(/([A-Z]+)([A-Z][a-z])/g, "$1_$2") // "APIDoc" → "API_Doc"
    26→    .replace(/([a-z\d])([A-Z])/g, "$1_$2")       // "appComponent" → "app_Component"
    27→    .toLowerCase();
    28→}
    29→
    30→/**
    31→ * Derive a snake_case file stem for a given element type.
    32→ * Uses the spec node title for accurate word boundaries (e.g., "InputSpacePartition" → "input_space_partition").
    33→ * Falls back to the raw type string when the title is unavailable.
    34→ */
    35→function typeToSnakeStem(specNodeId: string | undefined, type: string): string {
    36→  if (specNodeId) {
    37→    const nodeType = getNodeType(specNodeId as SpecNodeId);
    38→    if (nodeType?.title) {
    39→      return titleToSnakeCase(nodeType.title);
    40→    }
    41→  }
    42→  return type;
    43→}
    44→
    45→// Fallback for runtime environments where TELEMETRY_ENABLED is not defined by esbuild
    46→declare const TELEMETRY_ENABLED: boolean | undefined;
    47→const isTelemetryEnabled = typeof TELEMETRY_ENABLED !== "undefined" ? TELEMETRY_ENABLED : false;
    48→
    49→/**
    50→ * Model class representing the complete architecture model
    51→ * Uses GraphModel internally for graph-based storage
    52→ */
    53→export class Model {
    54→  rootPath: string;
    55→  manifest: Manifest;
    56→  graph: GraphModel;
    57→  layers: Map<string, Layer>;
    58→  relationships: Relationships;
    59→  lazyLoad: boolean;
    60→  private loadedLayers: Set<string>;
    61→  private virtualProjectionEngine?: VirtualProjectionEngine;
    62→
    63→  constructor(rootPath: string, manifest: Manifest, options: ModelOptions = {}) {
    64→    this.rootPath = rootPath;
    65→    this.manifest = manifest;
    66→    this.graph = new GraphModel();
    67→    this.layers = new Map();
    68→    this.relationships = new Relationships();
    69→    this.lazyLoad = options.lazyLoad ?? false;
    70→    this.loadedLayers = new Set();
    71→  }
    72→
    73→  /**
    74→   * Get a layer, loading it if lazy loading is enabled
    75→   */
    76→  async getLayer(name: string): Promise<Layer | undefined> {
    77→    if (this.lazyLoad && !this.loadedLayers.has(name)) {
    78→      await this.loadLayer(name);
    79→    }
    80→    return this.layers.get(name);
    81→  }
    82→
    83→  /**
    84→   * Get an element by ID across all layers
    85→   * Supports both UUID and semantic ID (layer.type.kebab-name) lookup
    86→   */
    87→  getElementById(id: string): Element | undefined {
    88→    for (const layer of this.layers.values()) {
    89→      const element = layer.getElement(id);
    90→      if (element) {
    91→        return element;
    92→      }
    93→    }
    94→    return undefined;
    95→  }
    96→
    97→  /**
    98→   * Get virtual projection engine (lazily initialized)
    99→   */
   100→  getVirtualProjectionEngine(): VirtualProjectionEngine {
   101→    if (!this.virtualProjectionEngine) {
   102→      this.virtualProjectionEngine = new VirtualProjectionEngine(this.rootPath);
   103→    }
   104→    return this.virtualProjectionEngine;
   105→  }
   106→
   107→  /**
   108→   * Load a layer from disk (model/XX_layername/*.yaml files)
   109→   */
   110→  async loadLayer(name: string): Promise<void> {
   111→    const layerSpan = isTelemetryEnabled
   112→      ? startSpan("layer.load", {
   113→          "layer.name": name,
   114→        })
   115→      : null;
   116→
   117→    try {
   118→      const fs = await import("fs/promises");
   119→      const yaml = await import("yaml");
   120→
   121→      let layerPath: string | null = null;
   122→
   123→      // Auto-discover by scanning directory with naming convention
   124→      const modelDir = `${this.rootPath}/documentation-robotics/model`;
   125→
   126→      try {
   127→        const entries = await fs.readdir(modelDir, { withFileTypes: true });
   128→        const layerDir = entries.find(
   129→          (e) =>
   130→            e.isDirectory() && e.name.match(/^\d{2}_/) && e.name.replace(/^\d{2}_/, "") === name
   131→        );
   132→
   133→        if (layerDir) {
   134→          layerPath = `${modelDir}/${layerDir.name}`;
   135→        }
   136→      } catch {
   137→        // Model directory doesn't exist or can't be read
   138→      }
   139→
   140→      if (!layerPath) {
   141→        return; // Layer directory not found
   142→      }
   143→
   144→      const layer = new Layer(name, this.graph);
   145→      let parseErrorCount = 0;
   146→
   147→      // Load all YAML files in the layer directory
   148→      const files = await fs.readdir(layerPath);
   149→      for (const file of files) {
   150→        if (file.endsWith(".yaml") || file.endsWith(".yml")) {
   151→          const filePath = `${layerPath}/${file}`;
   152→          try {
   153→            const yamlContent = await fs.readFile(filePath, "utf-8");
   154→            const elements = yaml.parse(yamlContent);
   155→
   156→            // Add each element from the YAML file
   157→            if (elements && typeof elements === "object") {
   158→              for (const [key, element] of Object.entries(elements)) {
   159→                if (element && typeof element === "object") {
   160→                  const el: any = element;
   161→
   162→                  let elementUUID = el.id;
   163→                  let extractedType: string | undefined = undefined;
   164→
   165→                  // Legacy format detection:
   166→                  // 1. Dot-separated semantic IDs (e.g., "motivation.goal.test-goal") with 2+ dots
   167→                  // 2. Hyphen-separated legacy format (e.g., "motivation-goal-test-goal")
   168→                  if (typeof elementUUID === "string") {
   169→                    const dotCount = (elementUUID.match(/\./g) || []).length;
   170→                    const isSemanticId = dotCount >= 2;
   171→                    const isLegacyHyphenFormat =
   172→                      !isSemanticId && // Not a semantic ID
   173→                      elementUUID.includes("-") && // Has hyphens
   174→                      elementUUID.startsWith(name) && // Starts with layer name
   175→                      elementUUID.length > name.length + 1; // Has more than just layer name
   176→
   177→                    if (isSemanticId || isLegacyHyphenFormat) {
   178→                      // Extract type from semantic ID format: "layer.type.kebab-case-name"
   179→                      // or legacy format: "layer-type-kebab-case-name"
   180→                      const parts = elementUUID.split(/[.-]/);
   181→                      if (parts.length >= 3) {
   182→                        // Skip first part (layer name), get second part (type)
   183→                        extractedType = parts[1];
   184→                      } else if (parts.length === 2) {
   185→                        // Fallback for simple format
   186→                        extractedType = parts[1];
   187→                      }
   188→
   189→                      // Generate a UUID for the element
   190→                      elementUUID = crypto.randomUUID();
   191→                    }
   192→                  }
   193→
   194→                  const elementName = el.name || key;
   195→                  const elementType = el.type || extractedType;
   196→                  const layerId = el.layer_id || name;
   197→
   198→                  const newElement = new Element({
   199→                    id: elementUUID,
   200→                    spec_node_id: el.spec_node_id,
   201→                    layer_id: layerId,
   202→                    attributes: el.attributes,
   203→                    source_reference: el.source_reference,
   204→                    metadata: el.metadata,
   205→                    name: elementName,
   206→                    type: elementType,
   207→                    description: el.description || "",
   208→                    relationships: el.relationships || [],
   209→                    references: el.references || [],
   210→                    layer: layerId,
   211→                  });
   212→                  layer.addElement(newElement);
   213→                }
   214→              }
   215→            }
   216→          } catch (fileError) {
   217→            // Log YAML parsing errors but continue loading other files
   218→            const errorMsg = fileError instanceof Error ? fileError.message : String(fileError);
   219→            console.error(`Warning: Failed to parse ${filePath}: ${errorMsg}`);
   220→            parseErrorCount++;
   221→            // Continue with next file
   222→          }
   223→        }
   224→      }
   225→
   226→      // If we had parse errors, add a note to the layer
   227→      if (parseErrorCount > 0) {
   228→        console.error(
   229→          `Warning: Layer '${name}' loaded with ${parseErrorCount} YAML parse error(s)`
   230→        );
   231→      }
   232→
   233→      this.layers.set(name, layer);
   234→      this.loadedLayers.add(name);
   235→
   236→      if (isTelemetryEnabled && layerSpan) {
   237→        layerSpan.setAttribute("layer.element_count", layer.elements.size);
   238→      }
   239→    } finally {
   240→      if (isTelemetryEnabled) {
   241→        endSpan(layerSpan);
   242→      }
   243→    }
   244→  }
   245→
   246→  /**
   247→   * Add a layer to the model
   248→   */
   249→  addLayer(layer: Layer): void {
   250→    // If the layer has elements in its isolated graph, migrate them to the model's graph
   251→    if (layer.graph.getNodeCount() > 0) {
   252→      for (const node of layer.graph.nodes.values()) {
   253→        this.graph.addNode(node);
   254→      }
   255→      for (const edge of layer.graph.edges.values()) {
   256→        this.graph.addEdge(edge);
   257→      }
   258→    }
   259→    // Ensure layer uses the model's graph for future operations
   260→    layer.graph = this.graph;
   261→    this.layers.set(layer.name, layer);
   262→    this.loadedLayers.add(layer.name);
   263→  }
   264→
   265→  /**
   266→   * Get all loaded layer names
   267→   */
   268→  getLayerNames(): string[] {
   269→    return Array.from(this.layers.keys());
   270→  }
   271→
   272→  /**
   273→   * Save a layer to disk (model/XX_layername/*.yaml)
   274→   */
   275→  async saveLayer(name: string): Promise<void> {
   276→    const layer = this.layers.get(name);
   277→    if (!layer) {
   278→      throw new Error(`Layer ${name} not found`);
   279→    }
   280→
   281→    const fs = await import("fs/promises");
   282→    const yaml = await import("yaml");
   283→
   284→    let layerPath: string | null = null;
   285→
   286→    // Discover by scanning directory
   287→    const modelDir = `${this.rootPath}/documentation-robotics/model`;
   288→
   289→    try {
   290→      const entries = await fs.readdir(modelDir, { withFileTypes: true });
   291→      const layerDir = entries.find(
   292→        (e) =>
   293→          e.isDirectory() && e.name.match(/^\d{2}_/) && e.name.replace(/^\d{2}_/, "") === name
   294→      );
   295→
   296→      if (layerDir) {
   297→        layerPath = `${modelDir}/${layerDir.name}`;
   298→      }
   299→    } catch {
   300→      // Model directory doesn't exist or can't be read
   301→    }
   302→
   303→    // If still not found, create using default format
   304→    if (!layerPath) {
   305→      // Find the order number for this layer
   306→      // Handle layer names with or without numeric prefix (e.g., "motivation" or "01-motivation")
   307→      const layerNameWithoutPrefix = name.replace(/^\d{2}-/, "");
   308→      const index = CANONICAL_LAYER_NAMES.indexOf(layerNameWithoutPrefix as typeof CANONICAL_LAYER_NAMES[number]);
   309→      if (index >= 0) {
   310→        const orderNum = String(index + 1).padStart(2, "0");
   311→        layerPath = `${this.rootPath}/documentation-robotics/model/${orderNum}_${layerNameWithoutPrefix}`;
   312→        await ensureDir(layerPath);
   313→      } else {
   314→        throw new Error(`Unknown layer ${name} and no path configured in manifest`);
   315→      }
   316→    }
   317→
   318→    // Delete all existing YAML files in the layer directory to ensure
   319→    // we don't keep stale files after element deletion
   320→    try {
   321→      const existingFiles = await fs.readdir(layerPath);
   322→      for (const file of existingFiles) {
   323→        if (file.endsWith(".yaml") || file.endsWith(".yml")) {
   324→          await fs.unlink(`${layerPath}/${file}`);
   325→        }
   326→      }
   327→    } catch (err) {
   328→      // Only ignore "directory not found" errors — re-throw permission/I/O errors
   329→      const isNotFoundError = (err as any)?.code === "ENOENT";
   330→      if (!isNotFoundError) {
   331→        throw new Error(
   332→          `Failed to clean existing YAML files: ${err instanceof Error ? err.message : String(err)}`
   333→        );
   334→      }
   335→    }
   336→
   337→    // Group elements by type, computing the snake_case file stem from the spec node title
   338→    const elementsByType = new Map<string, { stem: string; elements: Element[] }>();
   339→    for (const element of layer.elements.values()) {
   340→      const typeKey = element.type;
   341→      if (!elementsByType.has(typeKey)) {
   342→        const stem = typeToSnakeStem(element.spec_node_id, element.type);
   343→        elementsByType.set(typeKey, { stem, elements: [] });
   344→      }
   345→      elementsByType.get(typeKey)!.elements.push(element);
   346→    }
   347→
   348→    // Internal graph fields — never written to YAML
   349→    const INTERNAL_FIELDS = new Set([
   350→      "__references__", "__relationships__",
   351→      "source", "x-source-reference",
   352→    ]);
   353→
   354→    // Write each type to its own YAML file
   355→    for (const [, { stem, elements }] of elementsByType) {
   356→      const filename = `${stem}.yaml`;
   357→      const filePath = `${layerPath}/${filename}`;
   358→
   359→      // Convert elements to spec-node format YAML
   360→      const yamlData: any = {};
   361→      for (const element of elements) {
   362→        const json = element.toJSON();
   363→
   364→        // Clean attributes: remove graph-internal keys that should not be persisted
   365→        const cleanAttrs = json.attributes
   366→          ? Object.fromEntries(
   367→              Object.entries(json.attributes).filter(([k]) => !INTERNAL_FIELDS.has(k))
   368→            )
   369→          : undefined;
   370→
   371→        // Use UUID as YAML key
   372→        const key = element.id;
   373→        yamlData[key] = {
   374→          id: json.id,
   375→          spec_node_id: json.spec_node_id,
   376→          type: json.type,
   377→          layer_id: json.layer_id,
   378→          name: json.name,
   379→          ...(json.description && { description: json.description }),
   380→          ...(cleanAttrs && Object.keys(cleanAttrs).length > 0 && { attributes: cleanAttrs }),
   381→          ...(json.source_reference && { source_reference: json.source_reference }),
   382→          ...(json.metadata && { metadata: json.metadata }),
   383→          ...(json.references && json.references.length > 0 && { references: json.references }),
   384→          // Relationships are now stored in centralized relationships.yaml, not inline
   385→        };
   386→      }
   387→
   388→      await writeFile(filePath, yaml.stringify(yamlData));
   389→    }
   390→
   391→    layer.markClean();
   392→  }
   393→
   394→  /**
   395→   * Save model (saves all dirty layers and manifest)
   396→   */
   397→  async save(): Promise<void> {
   398→    await this.saveDirtyLayers();
   399→    await this.saveManifest();
   400→  }
   401→
   402→  /**
   403→   * Save all dirty layers to disk
   404→   */
   405→  async saveDirtyLayers(): Promise<void> {
   406→    // Count dirty layers before operation
   407→    let dirtyLayerCount = 0;
   408→    for (const layer of this.layers.values()) {
   409→      if (layer.isDirty()) {
   410→        dirtyLayerCount++;
   411→      }
   412→    }
   413→
   414→    const span = isTelemetryEnabled
   415→      ? startSpan("model.save", {
   416→          "model.path": this.rootPath,
   417→          "model.dirty_layer_count": dirtyLayerCount,
   418→        })
   419→      : null;
   420→
   421→    try {
   422→      for (const layer of this.layers.values()) {
   423→        if (layer.isDirty()) {
   424→          await this.saveLayer(layer.name);
   425→        }
   426→      }
   427→    } finally {
   428→      if (isTelemetryEnabled) {
   429→        endSpan(span);
   430→      }
   431→    }
   432→  }
   433→
   434→  /**
   435→   * Save the manifest to disk (documentation-robotics/model/manifest.yaml)
   436→   */
   437→  async saveManifest(): Promise<void> {
   438→    this.manifest.updateModified();
   439→    const yaml = await import("yaml");
   440→    const manifestPath = `${this.rootPath}/documentation-robotics/model/manifest.yaml`;
   441→
   442→    // Convert to YAML format
   443→    const yamlData: any = {
   444→      version: this.manifest.version,
   445→      schema: "documentation-robotics-v1",
   446→      cli_version: getCliVersion(),
   447→      spec_version: this.manifest.specVersion,
   448→      created: this.manifest.created,
   449→      updated: this.manifest.modified,
   450→      project: {
   451→        name: this.manifest.name,
   452→        description: this.manifest.description,
   453→        version: this.manifest.version,
   454→      },
   455→      documentation: ".dr/README.md",
   456→      layers: {},
   457→    };
   458→
   459→    // Generate layer structure from current model state
   460→    const layerOrder = [
   461→      "motivation",
   462→      "business",
   463→      "security",
   464→      "application",
   465→      "technology",
   466→      "api",
   467→      "data-model",
   468→      "data-store",
   469→      "ux",
   470→      "navigation",
   471→      "apm",
   472→      "testing",
   473→    ];
   474→
   475→    for (let i = 0; i < layerOrder.length; i++) {
   476→      const layerName = layerOrder[i];
   477→      const layer = this.layers.get(layerName);
   478→      const orderNum = String(i + 1).padStart(2, "0");
   479→
   480→      yamlData.layers[layerName] = {
   481→        order: i + 1,
   482→        name: layerName.charAt(0).toUpperCase() + layerName.slice(1).replace("-", " "),
   483→        path: `documentation-robotics/model/${orderNum}_${layerName}/`,
   484→        enabled: true,
   485→        ...(layer && { elements: this.getLayerElementCounts(layer) }),
   486→      };
   487→    }
   488→
   489→    if (this.manifest.changeset_history && this.manifest.changeset_history.length > 0) {
   490→      yamlData.changeset_history = this.manifest.changeset_history;
   491→    }
   492→
   493→    await ensureDir(`${this.rootPath}/documentation-robotics/model`);
   494→    await writeFile(manifestPath, yaml.stringify(yamlData));
   495→  }
   496→
   497→  private getLayerElementCounts(layer: Layer): Record<string, number> {
   498→    const counts: Record<string, number> = {};
   499→    for (const element of layer.elements.values()) {
   500→      counts[element.type] = (counts[element.type] || 0) + 1;
   501→    }
   502→    return counts;
   503→  }
   504→
   505→  /**
   506→   * Load relationships from relationships.yaml
   507→   */
   508→  async loadRelationships(): Promise<void> {
   509→    const fs = await import("fs/promises");
   510→    const yaml = await import("yaml");
   511→    const relationshipsPath = `${this.rootPath}/documentation-robotics/model/relationships.yaml`;
   512→
   513→    try {
   514→      const yamlContent = await fs.readFile(relationshipsPath, "utf-8");
   515→      const data = yaml.parse(yamlContent);
   516→
   517→      if (Array.isArray(data)) {
   518→        this.relationships = Relationships.fromArray(data);
   519→        // Sync relationships to graph
   520→        for (let i = 0; i < data.length; i++) {
   521→          const rel = data[i];
   522→          const edge: GraphEdge = {
   523→            id: `rel-${i}-${crypto.randomBytes(4).toString("hex")}`,
   524→            source: rel.source,
   525→            destination: rel.target,
   526→            predicate: rel.predicate,
   527→            properties: rel.properties,
   528→            category: rel.category,
   529→          };
   530→          this.graph.addEdge(edge);
   531→        }
   532→      }
   533→    } catch (err) {
   534→      // If file doesn't exist, that's okay - start with empty relationships
   535→      if ((err as any).code !== "ENOENT") {
   536→        // But if it's a different error, we should know about it
   537→        if (process.env.DEBUG) {
   538→          console.debug(`Warning: Failed to load relationships.yaml: ${err}`);
   539→        }
   540→      }
   541→    }
   542→  }
   543→
   544→  /**
   545→   * Save relationships to relationships.yaml
   546→   */
   547→  async saveRelationships(): Promise<void> {
   548→    const fs = await import("fs/promises");
   549→    const yaml = await import("yaml");
   550→    const relationshipsPath = `${this.rootPath}/documentation-robotics/model/relationships.yaml`;
   551→
   552→    await ensureDir(`${this.rootPath}/documentation-robotics/model`);
   553→
   554→    const data = this.relationships.toArray();
   555→
   556→    // Add header comment with timestamp to ensure file always changes
   557→    const timestamp = new Date().toISOString();
   558→    const header = `# Intra-layer relationships
   559→# Format: source_id -> predicate -> target_id
   560→# Last updated: ${timestamp}
   561→
   562→`;
   563→    const yamlContent = header + yaml.stringify(data);
   564→
   565→    await fs.writeFile(relationshipsPath, yamlContent, "utf-8");
   566→    this.relationships.markClean();
   567→  }
