   572→   * @param startPath - Starting path for search
   573→   * @returns Project root and manifest path
   574→   */
   575→  private static async resolveModelPaths(startPath?: string): Promise<{
   576→    projectRoot: string;
   577→    manifestPath: string;
   578→  }> {
   579→    const searchPath = startPath || process.cwd();
   580→
   581→    // Optional override via env var (highest priority)
   582→    if (process.env.DR_MODEL_PATH) {
   583→      const envPath = path.resolve(process.env.DR_MODEL_PATH);
   584→      let manifestPath: string;
   585→
   586→      if (envPath.endsWith("manifest.yaml")) {
   587→        manifestPath = envPath;
   588→      } else if (envPath.endsWith("model")) {
   589→        manifestPath = path.join(envPath, "manifest.yaml");
   590→      } else {
   591→        manifestPath = path.join(envPath, "documentation-robotics", "model", "manifest.yaml");
   592→      }
   593→
   594→      try {
   595→        await fs.access(manifestPath);
   596→        const projectRoot = path.dirname(path.dirname(path.dirname(manifestPath)));
   597→        return { projectRoot, manifestPath: path.normalize(manifestPath) };
   598→      } catch {
   599→        throw new Error(`Model not found at DR_MODEL_PATH: ${process.env.DR_MODEL_PATH}`);
   600→      }
   601→    }
   602→
   603→    // Use findProjectRoot to locate documentation_robotics/ folder
   604→    const projectRoot = await findProjectRoot(searchPath);
   605→
   606→    if (!projectRoot) {
   607→      throw new Error(
   608→        "No DR project found. Could not find documentation_robotics/ folder.\n" +
   609→          'Run "dr init" to create a new project, or navigate to a directory containing a DR project.'
   610→      );
   611→    }
   612→
   613→    const manifestPath = path.join(projectRoot, "documentation-robotics", "model", "manifest.yaml");
   614→
   615→    try {
   616→      await fs.access(manifestPath);
   617→      return { projectRoot, manifestPath };
   618→    } catch {
   619→      throw new Error(
   620→        `Found documentation_robotics/ at ${projectRoot} but no model found. ` +
   621→          `Expected: ${manifestPath}\n` +
   622→          `Run "dr init" to create a model.`
   623→      );
   624→    }
   625→  }
