   814→  /**
   815→   * Create a backup of the current model state
   816→   * Used for rollback support in migration operations
   817→   *
   818→   * @param label Descriptive label for the backup (e.g., "pre-migration")
   819→   * @returns Path to the backup directory
   820→   */
   821→  async createBackup(label: string): Promise<string> {
   822→    const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
   823→    const backupDir = path.join(this.rootPath, ".dr-backups", `${label}-${timestamp}`);
   824→
   825→    // Create backup directory
   826→    await ensureDir(backupDir);
   827→
   828→    // Backup layers directory
   829→    const layersSource = path.join(this.rootPath, "documentation-robotics", "model");
   830→    const layersBackup = path.join(backupDir, "layers");
   831→    if (await this.directoryExists(layersSource)) {
   832→      await this.copyDirectory(layersSource, layersBackup);
   833→    }
   834→
   835→    // Backup manifest
   836→    const manifestSource = path.join(this.rootPath, "documentation-robotics", "model", "manifest.yaml");
   837→    const manifestBackup = path.join(backupDir, "manifest.yaml");
   838→    if (await this.fileExists(manifestSource)) {
   839→      await fs.copyFile(manifestSource, manifestBackup);
   840→    }
   841→
   842→    return backupDir;
   843→  }
