    23→/**
    24→ * Graph edge representing a relationship between nodes
    25→ */
    26→export interface GraphEdge {
    27→  id: string; // Unique identifier
    28→  source: string; // Source node ID
    29→  destination: string; // Destination node ID
    30→  predicate: string; // Relationship type
    31→  properties?: Record<string, unknown>; // Optional properties
    32→  category?: "structural" | "behavioral";
    33→}
    34→
    35→/**
    36→ * Index structures for efficient querying
    37→ */
    38→interface GraphIndices {
    39→  nodesByLayer: Map<string, Set<string>>; // layer -> node IDs
    40→  nodesByType: Map<string, Set<string>>; // type -> node IDs
    41→  edgesBySource: Map<string, Set<string>>; // source node ID -> edge IDs
    42→  edgesByDestination: Map<string, Set<string>>; // destination node ID -> edge IDs
    43→  edgesByPredicate: Map<string, Set<string>>; // predicate -> edge IDs
    44→}
    45→
    46→/**
    47→ * Graph model interface for node/edge storage with query capabilities
    48→ */
    49→export interface IGraphModel {
    50→  nodes: Map<string, GraphNode>;
    51→  edges: Map<string, GraphEdge>;
    52→
    53→  // Query methods
    54→  getNode(id: string): GraphNode | undefined;
    55→  getNodesByLayer(layer: string): GraphNode[];
    56→  getNodesByType(type: string): GraphNode[];
    57→  getEdgesFrom(nodeId: string, predicate?: string): GraphEdge[];
    58→  getEdgesTo(nodeId: string, predicate?: string): GraphEdge[];
    59→  getEdgesBetween(sourceId: string, destinationId: string, predicate?: string): GraphEdge[];
    60→  getAllEdges(): GraphEdge[];
    61→
    62→  // Mutation methods
    63→  addNode(node: GraphNode): void;
    64→  removeNode(nodeId: string): boolean;
    65→  updateNode(nodeId: string, updates: Partial<GraphNode>): boolean;
    66→
    67→  addEdge(edge: GraphEdge): void;
    68→  removeEdge(edgeId: string): boolean;
    69→  updateEdge(edgeId: string, updates: Partial<GraphEdge>): boolean;
    70→
    71→  // Traversal
    72→  traverse(startNodeId: string, predicate?: string, maxDepth?: number): GraphNode[];
