    80→/**
    81→ * Implementation of graph model with indices for efficient queries
    82→ */
    83→export class GraphModel implements IGraphModel {
    84→  nodes: Map<string, GraphNode>;
    85→  edges: Map<string, GraphEdge>;
    86→  private indices: GraphIndices;
    87→  private nodesVersion: number = 0;
    88→
    89→  constructor() {
    90→    this.nodes = new Map();
    91→    this.edges = new Map();
    92→    this.indices = {
    93→      nodesByLayer: new Map(),
    94→      nodesByType: new Map(),
    95→      edgesBySource: new Map(),
    96→      edgesByDestination: new Map(),
    97→      edgesByPredicate: new Map(),
    98→    };
    99→  }
   100→
   101→  /**
   102→   * Get the current version of the nodes (for cache invalidation)
   103→   */
   104→  getNodesVersion(): number {
   105→    return this.nodesVersion;
   106→  }
   107→
   108→  /**
   109→   * Add a node to the graph and update indices
   110→   * If a node with the same ID exists, its old index entries are cleaned up
   111→   */
   112→  addNode(node: GraphNode): void {
   113→    const existingNode = this.nodes.get(node.id);
   114→
   115→    // Clean up old index entries if node is being replaced
   116→    if (existingNode) {
   117→      // Remove from old layer index
   118→      const oldLayerSet = this.indices.nodesByLayer.get(existingNode.layer);
   119→      if (oldLayerSet) {
   120→        oldLayerSet.delete(node.id);
   121→        if (oldLayerSet.size === 0) {
   122→          this.indices.nodesByLayer.delete(existingNode.layer);
   123→        }
   124→      }
   125→
   126→      // Remove from old type index
   127→      const oldTypeSet = this.indices.nodesByType.get(existingNode.type);
   128→      if (oldTypeSet) {
   129→        oldTypeSet.delete(node.id);
   130→        if (oldTypeSet.size === 0) {
   131→          this.indices.nodesByType.delete(existingNode.type);
   132→        }
   133→      }
   134→    }
   135→
   136→    // Add new node
   137→    this.nodes.set(node.id, node);
   138→
   139→    // Update layer index
   140→    if (!this.indices.nodesByLayer.has(node.layer)) {
   141→      this.indices.nodesByLayer.set(node.layer, new Set());
   142→    }
   143→    const layerSet = this.indices.nodesByLayer.get(node.layer);
   144→    if (layerSet) {
   145→      layerSet.add(node.id);
   146→    }
   147→
   148→    // Update type index
   149→    if (!this.indices.nodesByType.has(node.type)) {
