   214→    const isHyphenSeparated = semanticId.includes("-") && semanticId.startsWith(this.name) && semanticId.length > this.name.length + 1;
   215→
   216→    if (!isDotSeparated && !isHyphenSeparated) {
   217→      return undefined;
   218→    }
   219→
   220→    // Search all nodes in the layer
   221→    for (const candidate of this.graph.nodes.values()) {
   222→      if (candidate.layer !== this.name) {
   223→        continue;
   224→      }
   225→
   226→      // Build semantic IDs from element name
   227→      const kebabName = candidate.name
   228→        .replace(/[\s_]+/g, "-")
   229→        .replace(/([a-z])([A-Z])/g, "$1-$2")
   230→        .toLowerCase()
   231→        .replace(/-+/g, "-")
   232→        .replace(/^-+|-+$/g, "");
   233→
   234→      const semanticIds = [
   235→        `${candidate.layer_id || this.name}.${candidate.type}.${kebabName}`,
   236→        `${candidate.layer_id || this.name}-${candidate.type}-${kebabName}`,
   237→      ];
   238→
   239→      if (semanticIds.includes(semanticId)) {
   240→        return new Element({
   241→          id: candidate.id,
   242→          spec_node_id: candidate.spec_node_id,
   243→          layer_id: candidate.layer_id,
   244→          type: candidate.type,
   245→          name: candidate.name,
   246→          description: candidate.description,
   247→          attributes: candidate.attributes,
   248→          source_reference: candidate.source_reference,
   249→          metadata: candidate.metadata,
   250→          layer: candidate.layer,
   251→          references: (candidate.properties["__references__"] ?? []) as Reference[],
   252→          relationships: (candidate.properties["__relationships__"] ?? []) as Relationship[],
   253→        });
   254→      }
   255→    }
   256→
   257→    return undefined;
   258→  }
   259→
   260→  /**
   261→   * Update an element in the graph
   262→   */
   263→  updateElement(element: Element): boolean {
   264→    const node = this.graph.nodes.get(element.id);
   265→    if (!node || node.layer !== this.name) {
   266→      return false;
   267→    }
   268→
   269→    // Prepare properties including references and relationships
   270→    // Start with existing node properties to preserve graph metadata fields like __references__ and __relationships__
   271→    const properties = { ...node.properties };
   272→
   273→    // Persist references and relationships as node properties
   274→    if (element.references && element.references.length > 0) {
   275→      properties["__references__"] = element.references;
   276→    } else {
   277→      delete properties["__references__"];
   278→    }
   279→
   280→    if (element.relationships && element.relationships.length > 0) {
   281→      properties["__relationships__"] = element.relationships;
   282→    } else {
   283→      delete properties["__relationships__"];
   284→    }
   285→
   286→    // Convert element to graph node and update in place, including spec-node fields
   287→    // so that source_reference and attributes changes aren't lost on the next save cycle
   288→    const updated = this.graph.updateNode(element.id, {
   289→      name: element.name,
   290→      description: element.description,
   291→      properties,
   292→      spec_node_id: element.spec_node_id || undefined,
   293→      layer_id: element.layer_id || undefined,
   294→      attributes: element.attributes,
   295→      source_reference: element.source_reference,
   296→      metadata: element.metadata,
   297→    });
   298→
   299→    if (updated) {
   300→      this.dirty = true;
   301→    }
   302→    return updated;
   303→  }
   304→
   305→  /**
   306→   * Delete an element by ID from the graph
   307→   *
   308→   * @param id - UUID of the element to delete
   309→   * @returns true if element was deleted, false if not found
   310→   */
   311→  deleteElement(id: string): boolean {
   312→    const node = this.graph.nodes.get(id);
   313→
   314→    if (!node || node.layer !== this.name) {
   315→      return false;
   316→    }
   317→
   318→    const result = this.graph.removeNode(node.id);
   319→    if (result) {
   320→      this.dirty = true;
   321→    }
   322→    return result;
   323→  }
   324→
   325→  /**
   326→   * List all elements in the layer from the graph
   327→   */
   328→  listElements(): Element[] {
   329→    const nodes = this.graph.getNodesByLayer(this.name);
   330→    return nodes.map(
   331→      (node) =>
   332→        new Element({
   333→          id: node.id,
   334→          spec_node_id: node.spec_node_id,
   335→          layer_id: node.layer_id,
   336→          type: node.type,
   337→          name: node.name,
   338→          description: node.description,
   339→          attributes: node.attributes,
   340→          source_reference: node.source_reference,
   341→          metadata: node.metadata,
   342→          layer: node.layer,
   343→          references: (node.properties["__references__"] ?? []) as Reference[],
   344→          relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   345→        })
   346→    );
   347→  }
   348→
   349→  /**
   350→   * Check if layer has unsaved changes
   351→   */
   352→  isDirty(): boolean {
   353→    return this.dirty;
   354→  }
   355→
   356→  /**
   357→   * Mark layer as clean (no unsaved changes)
   358→   */
   359→  markClean(): void {
   360→    this.dirty = false;
   361→  }
   362→
   363→  /**
   364→   * Serialize to JSON representation
   365→   */
   366→  toJSON(): LayerData {
   367→    const result: LayerData = {
   368→      elements: this.listElements().map((e) => e.toJSON()),
   369→    };
   370→
   371→    if (this.metadata) {
   372→      result.metadata = this.metadata;
   373→    }
   374→
   375→    return result;
   376→  }
   377→
   378→  /**
   379→   * Create Layer from JSON data
   380→   */
   381→  static fromJSON(name: string, data: LayerData, graph?: GraphModel): Layer {
   382→    const elements = data.elements.map(
   383→      (e) =>
   384→        new Element({
   385→          id: e.id,
   386→          spec_node_id: e.spec_node_id,
   387→          layer_id: e.layer_id,
   388→          type: e.type,
   389→          name: e.name,
   390→          description: e.description,
   391→          attributes: e.attributes,
   392→          source_reference: e.source_reference,
   393→          metadata: e.metadata,
   394→          references: e.references,
   395→          relationships: e.relationships,
   396→          layer: name,
   397→        })
   398→    );
   399→    const layer = new Layer(name, graph, elements);
   400→    layer.metadata = data.metadata;
   401→    return layer;
   402→  }
   403→}
   404→

