   136→    const element = new Element({
   137→      id: randomUUID(),
   138→      spec_node_id: `${layer}.${type}`,
   139→      layer_id: layer,
   140→      type: type,
   141→      name: options.name || name,
   142→      description: options.description,
   143→      attributes: attributes,
   144→      metadata: {
   145→        created_at: new Date().toISOString(),
   146→        updated_at: new Date().toISOString(),
   147→        version: 1,
   148→      },
   149→      layer, // Set layer so setSourceReference can use it
   150→    });
   151→
   152→    // Store the semantic name component (third positional arg) for semantic ID lookup
   153→    if (options.name && options.name !== name) {
   154→      element.attributes["semanticName"] = name;
   155→    }
   156→
   157→    // Add source reference if provided
   158→    const sourceRef = buildSourceReference(options);
   159→    if (sourceRef) {
   160→      element.setSourceReference(sourceRef);
   161→    }
   162→
   163→    // Check if element already exists
   164→    if (layerObj.getElement(elementId)) {
   165→      throw new CLIError(
   166→        `Element ${elementId} already exists in ${layer} layer`,
   167→        ErrorCategory.USER,
   168→        [
   169→          `Use "dr show ${elementId}" to view the existing element`,
   170→          `Use "dr update ${elementId}" to modify it`,
   171→          `Use "dr delete ${elementId}" to remove it first if you want to recreate it`,
   172→        ],
   173→        { operation: "add", context: `Duplicate element ID` }
   174→      );
   175→    }
   176→
   177→    // Unified mutation handler for add operation
   178→    const handler = new MutationHandler(model, elementId, layer);
   179→
   180→    // Execute add through unified path (handles staging and base model consistently)
   181→    await handler.executeAdd(element, (elem) => {
   182→      // This mutator is called by executeAdd for base model path only
   183→      layerObj.addElement(elem);
   184→    });
   185→
   186→    // Determine if operation was staged or applied to base model
   187→    if (handler.getAfterState()) {
   188→      // Check if we went through staging path
   189→      const stagingManager = handler.getStagingManager();
   190→      const activeChangeset = await stagingManager.getActive();
   191→      if (activeChangeset && activeChangeset.status === "staged") {
   192→        // Staging path
   193→        handleSuccess(
   194→          `Staged element ${ansis.bold(elementId)} to ${ansis.bold(activeChangeset.name)}`,
   195→          {
   196→            status: "staged",
   197→            changeset: activeChangeset.name,
   198→            type,
   199→            name: options.name || name,
   200→          }
   201→        );
   202→      } else {
   203→        // Base model path
   204→        handleSuccess(`Added element ${ansis.bold(elementId)} to ${ansis.bold(layer)} layer`, {
   205→          type,
   206→          name: options.name || name,
   207→          description: options.description || "(none)",
   208→        });
   209→      }
   210→    }
   211→  } catch (error) {
   212→    if (isTelemetryEnabled && span) {
   213→      (span as any).recordException(error as Error);
   214→      (span as any).setStatus({ code: 2, message: (error as Error).message });
   215→    }
   216→    handleError(error);
   217→  } finally {
   218→    if (isTelemetryEnabled) {
   219→      endSpan(span);
   220→    }
   221→  }
   222→}
