     1→/**
     2→ * Delete an element
     3→ */
     4→
     5→import { confirm } from "@clack/prompts";
     6→import ansis from "ansis";
     7→import { Model } from "../core/model.js";
     8→import { MutationHandler } from "../core/mutation-handler.js";
     9→import { ReferenceRegistry } from "../core/reference-registry.js";
    10→import { DependencyTracker, TraceDirection } from "../core/dependency-tracker.js";
    11→import { findElementLayer } from "../utils/element-utils.js";
    12→import { CLIError, handleError, ErrorCategory, ModelNotFoundError } from "../utils/errors.js";
    13→import { startSpan, endSpan } from "../telemetry/index.js";
    14→import { getErrorMessage } from "../utils/errors.js";
    15→
    16→declare const TELEMETRY_ENABLED: boolean | undefined;
    17→const isTelemetryEnabled = typeof TELEMETRY_ENABLED !== "undefined" ? TELEMETRY_ENABLED : false;
    18→
    19→export interface DeleteOptions {
    20→  force?: boolean;
    21→  verbose?: boolean;
    22→  debug?: boolean;
    23→  cascade?: boolean;
    24→  dryRun?: boolean;
    25→}
    26→
    27→export async function deleteCommand(id: string, options: DeleteOptions): Promise<void> {
    28→  const span = isTelemetryEnabled
    29→    ? startSpan("element.delete", {
    30→        "element.id": id,
    31→        "element.force": !!options.force,
    32→        "element.cascade": !!options.cascade,
    33→        "element.dryRun": !!options.dryRun,
    34→      })
    35→    : null;
    36→
    37→  try {
    38→    // Load model (with error handling for missing models)
    39→    let model: Model;
    40→    try {
    41→      model = await Model.load();
    42→    } catch (error) {
    43→      const message = getErrorMessage(error);
    44→      if (message.includes("No DR project") || message.includes("Model not found")) {
    45→        throw new ModelNotFoundError();
    46→      }
    47→      throw error;
    48→    }
    49→
    50→    // Find element
    51→    const layerName = await findElementLayer(model, id);
    52→    if (!layerName) {
    53→      throw new CLIError(`Element ${id} not found`, ErrorCategory.USER, [
    54→        `Use "dr search ${id}" to find similar elements`,
    55→        'Use "dr list <layer>" to list all elements in a layer',
    56→      ]);
    57→    }
    58→
    59→    const layer = (await model.getLayer(layerName))!;
    60→    const element = layer.getElement(id);
    61→
    62→    if (!element) {
    63→      throw new CLIError(`Element ${id} not found`, ErrorCategory.USER, [
    64→        `Use "dr search ${id}" to find similar elements`,
    65→        'Use "dr list <layer>" to list all elements in a layer',
    66→      ]);
    67→    }
    68→
    69→    // Build reference registry to track dependencies
    70→    const registry = new ReferenceRegistry();
    71→    for (const layer of model.layers.values()) {
    72→      for (const element of layer.listElements()) {
    73→        registry.registerElement(element);
    74→      }
    75→    }
    76→
    77→    // Create dependency tracker
    78→    const tracker = new DependencyTracker(registry, model);
    79→
    80→    // Find all elements that depend on this element (would be orphaned)
    81→    const dependents = tracker.traceDependencies(id, TraceDirection.DOWN, null);
    82→
    83→    // Display element information
    84→    console.log("");
    85→    console.log(ansis.bold(`Removing element: ${ansis.yellow(id)}`));
    86→    console.log(ansis.dim(`  Layer: ${layerName}`));
    87→    console.log(ansis.dim(`  Type: ${element.type || "unknown"}`));
    88→    if (element.name) {
    89→      console.log(ansis.dim(`  Name: ${element.name}`));
    90→    }
    91→
    92→    // Display dependencies if any exist
    93→    if (dependents.length > 0) {
    94→      console.log("");
    95→      console.log(
    96→        ansis.yellow(`⚠ Warning: This element has ${dependents.length} dependent element(s):`)
    97→      );
    98→
    99→      const directDependents = tracker.traceDependencies(id, TraceDirection.DOWN, 1);
   100→
   101→      // Show direct dependents
   102→      for (const dep of directDependents.slice(0, 5)) {
   103→        const depElement = model.getElementById(dep);
   104→        const depLayer = depElement?.layer || "unknown";
   105→        console.log(ansis.dim(`  - ${dep} (${depLayer})`));
   106→      }
   107→
   108→      if (directDependents.length > 5) {
   109→        console.log(ansis.dim(`  ... and ${directDependents.length - 5} more direct dependents`));
   110→      }
   111→
   112→      if (dependents.length > directDependents.length) {
   113→        console.log(
   114→          ansis.dim(
   115→            `  (${dependents.length - directDependents.length} transitive dependents not shown)`
   116→          )
   117→        );
   118→      }
   119→
   120→      // Check if cascade or force is enabled
   121→      if (!options.cascade && !options.force) {
   122→        console.log("");
   123→        console.log(ansis.red("✗ Cannot remove element with dependencies."));
   124→        console.log(ansis.dim("Use --cascade to remove all dependent elements"));
   125→        console.log(ansis.dim("or --force to skip dependency checks"));
   126→        const suggestions = [
   127→          `Use --dry-run with --cascade to preview what would be deleted`,
   128→          'Review dependencies before deletion using "dr show <element>"',
   129→          "Use --cascade to automatically remove all dependent elements",
   130→          "Or use --force to remove only this element (dependencies will reference a non-existent element)",
   131→        ];
   132→        throw new CLIError("Element has dependencies", ErrorCategory.USER, suggestions, {
   133→          operation: "delete",
   134→          relatedElements: directDependents.slice(0, 10),
   135→          context: `Element ${id} has ${dependents.length} dependent elements`,
   136→        });
   137→      }
   138→    }
   139→
   140→    // Calculate total elements to remove
   141→    const elementsToRemove = options.cascade ? [id, ...dependents] : [id];
   142→
   143→    // Display dry-run summary
   144→    if (options.dryRun) {
   145→      console.log("");
   146→      console.log(ansis.yellow(`Dry run - not removing`));
   147→      console.log(ansis.dim(`Would remove ${elementsToRemove.length} element(s)`));
   148→
   149→      if (options.cascade && dependents.length > 0) {
   150→        console.log("");
   151→        console.log(ansis.dim("Elements that would be removed:"));
   152→        console.log(ansis.dim(`  - ${id} (target)`));
   153→        for (const dep of dependents.slice(0, 10)) {
   154→          console.log(ansis.dim(`  - ${dep} (dependent)`));
   155→        }
   156→        if (dependents.length > 10) {
   157→          console.log(ansis.dim(`  ... and ${dependents.length - 10} more`));
   158→        }
   159→      }
   160→
   161→      return;
   162→    }
   163→
   164→    // Confirm deletion unless --force
   165→    if (!options.force) {
   166→      const message =
   167→        options.cascade && dependents.length > 0
   168→          ? `Delete ${ansis.bold(id)} and ${ansis.bold(String(dependents.length))} dependent element(s)? This cannot be undone.`
   169→          : `Delete element ${ansis.bold(id)}? This cannot be undone.`;
   170→
   171→      const confirmed = await confirm({
   172→        message,
   173→        initialValue: false,
   174→      });
   175→
   176→      if (!confirmed) {
   177→        console.log(ansis.dim("Cancelled"));
   178→        return;
   179→      }
   180→    }
   181→
   182→    // Execute deletion with error recovery guidance
   183→    let deletedCount = 0;
   184→    try {
   185→      if (options.cascade && dependents.length > 0) {
   186→        // Delete dependents first (reverse dependency order to avoid orphaned references)
   187→        const sortedDependents = [...dependents].reverse();
   188→
   189→        for (const depId of sortedDependents) {
   190→          try {
   191→            const depLayerName = await findElementLayer(model, depId);
   192→            if (!depLayerName) continue;
   193→
   194→            const depLayer = (await model.getLayer(depLayerName))!;
   195→            const depElement = depLayer.getElement(depId)!;
   196→
   197→            const handler = new MutationHandler(model, depId, depLayerName);
   198→            await handler.executeDelete(depElement);
   199→            deletedCount++;
   200→
   201→            if (options.verbose) {
   202→              console.log(ansis.dim(`  Deleted dependent: ${depId}`));
   203→            }
   204→          } catch (depError) {
   205→            // Track partial progress for error recovery
   206→            const suggestions = [
   207→              `${deletedCount} dependent element(s) were deleted before the error`,
   208→              'Check the model state with "dr validate" to identify any broken references',
   209→              'You may need to manually delete remaining elements or use "dr show" to inspect',
   210→            ];
   211→            throw new CLIError(
   212→              `Failed to delete dependent element ${depId}`,
   213→              ErrorCategory.SYSTEM,
   214→              suggestions,
   215→              {
   216→                operation: "delete (cascade)",
   217→                partialProgress: { completed: deletedCount, total: sortedDependents.length },
   218→                relatedElements: [id, ...sortedDependents.slice(0, 5)],
   219→              }
   220→            );
   221→          }
   222→        }
   223→      }
   224→    } catch (error) {
   225→      // If we're in the middle of cascade deletion, provide recovery info
   226→      if (options.cascade && deletedCount > 0 && !(error instanceof CLIError)) {
   227→        const suggestions = [
   228→          `${deletedCount} dependent element(s) were successfully deleted`,
   229→          'Use "dr validate" to check for broken references',
   230→          "The target element was not deleted - you can retry the operation",
   231→        ];
   232→        throw new CLIError(
   233→          "Cascade deletion was partially completed but encountered an error",
   234→          ErrorCategory.SYSTEM,
   235→          suggestions,
   236→          {
   237→            operation: "delete (cascade)",
   238→            partialProgress: { completed: deletedCount, total: dependents.length },
   239→          }
   240→        );
   241→      }
   242→      throw error;
   243→    }
   244→
   245→    // Delete the target element
   246→    const handler = new MutationHandler(model, id, layerName);
   247→    await handler.executeDelete(element);
   248→
   249→    if (isTelemetryEnabled && span) {
   250→      (span as any).setAttribute("layer.name", layerName);
   251→      (span as any).setAttribute("element.dependents", dependents.length);
   252→      (span as any).setAttribute("element.totalDeleted", elementsToRemove.length);
   253→    }
   254→
   255→    console.log("");
   256→    console.log(ansis.green(`✓ Deleted element ${ansis.bold(id)}`));
   257→
   258→    if (options.cascade && dependents.length > 0) {
   259→      console.log(ansis.green(`✓ Deleted ${dependents.length} dependent element(s)`));
   260→    }
   261→
   262→    if (options.verbose) {
   263→      console.log(ansis.dim(`  Layer: ${layerName}`));
   264→      console.log(ansis.dim(`  Total elements deleted: ${elementsToRemove.length}`));
   265→    }
   266→  } catch (error) {
   267→    if (isTelemetryEnabled && span) {
   268→      (span as any).recordException(error as Error);
   269→      (span as any).setStatus({ code: 2, message: (error as Error).message });
   270→    }
   271→    handleError(error);
   272→  } finally {
   273→    if (isTelemetryEnabled) {
   274→      endSpan(span);
   275→    }
   276→  }
   277→}
