     5→/**
     6→ * Layer class - thin wrapper over graph model for backward compatibility
     7→ * Queries the graph for elements in a specific layer
     8→ */
     9→export class Layer {
    10→  name: string;
    11→  graph: GraphModel;
    12→  metadata?: { layer: string; version: string };
    13→  private dirty: boolean = false;
    14→  private cachedElements: Map<string, Element> | null = null;
    15→  private cachedNodesVersion: number = 0;
    16→
    17→  constructor(
    18→    name: string,
    19→    elementsOrGraph?: Element[] | GraphModel,
    20→    elementsIfGraphPassed?: Element[]
    21→  ) {
    22→    this.name = name;
    23→
    24→    // Handle overloaded constructor:
    25→    // new Layer(name) - create with empty graph
    26→    // new Layer(name, elements) - create with elements array
    27→    // new Layer(name, graph) - create with provided graph
    28→    // new Layer(name, undefined, elements) - create with elements
    29→    // new Layer(name, graph, elements) - create with provided graph and elements
    30→    let actualGraph: GraphModel | undefined;
    31→    let elementsToAdd: Element[] = [];
    32→
    33→    if (elementsOrGraph instanceof GraphModel) {
    34→      // Called with graph as second parameter
    35→      actualGraph = elementsOrGraph;
    36→      // Elements are in the third parameter if provided
    37→      if (Array.isArray(elementsIfGraphPassed)) {
    38→        elementsToAdd = elementsIfGraphPassed;
    39→      }
    40→    } else if (Array.isArray(elementsOrGraph)) {
    41→      // Called with elements as second parameter
    42→      elementsToAdd = elementsOrGraph;
    43→    } else if (elementsOrGraph === undefined && Array.isArray(elementsIfGraphPassed)) {
    44→      // Called with undefined graph and elements in third parameter
    45→      elementsToAdd = elementsIfGraphPassed;
    46→    }
    47→
    48→    // Use provided graph or create a new one
    49→    this.graph = actualGraph || new GraphModel();
    50→
    51→    // Add elements to the graph (without marking as dirty during construction)
    52→    for (const element of elementsToAdd) {
    53→      // Ensure element has the correct layer
    54→      element.layer = this.name;
    55→      // Also set layer_id to maintain consistency with layer name
    56→      if (!element.layer_id || element.layer_id === "") {
    57→        element.layer_id = this.name;
    58→      }
    59→      const node = GraphModel.fromElement(element);
    60→
    61→      // Store references and relationships as node properties for preservation
    62→      if (element.references && element.references.length > 0) {
    63→        node.properties["__references__"] = element.references;
    64→      }
    65→      if (element.relationships && element.relationships.length > 0) {
    66→        node.properties["__relationships__"] = element.relationships;
    67→      }
    68→
    69→      this.graph.addNode(node);
    70→      // Don't mark as dirty during construction - elements added in constructor are initial state
    71→    }
    72→  }
    73→
    74→  /**
    75→   * Get all elements in this layer from the graph
    76→   * Converts graph nodes back to Elements for backward compatibility
    77→   * Results are cached and invalidated when the underlying graph changes
    78→   */
    79→  get elements(): Map<string, Element> {
    80→    const currentVersion = this.graph.getNodesVersion();
    81→
    82→    // Return cached result if graph hasn't changed
    83→    if (this.cachedElements !== null && this.cachedNodesVersion === currentVersion) {
    84→      return this.cachedElements;
    85→    }
    86→
    87→    // Rebuild cache
    88→    const result = new Map<string, Element>();
    89→    const nodes = this.graph.getNodesByLayer(this.name);
    90→
    91→    for (const node of nodes) {
    92→      const element = new Element({
    93→        id: node.id,
    94→        spec_node_id: node.spec_node_id,
    95→        layer_id: node.layer_id,
    96→        type: node.type,
    97→        name: node.name,
    98→        description: node.description,
    99→        attributes: node.attributes,
   100→        source_reference: node.source_reference,
   101→        metadata: node.metadata,
   102→        layer: node.layer,
   103→        references: (node.properties["__references__"] ?? []) as Reference[],
   104→        relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   105→      });
   106→      result.set(node.id, element);
   107→    }
   108→
   109→    this.cachedElements = result;
   110→    this.cachedNodesVersion = currentVersion;
   111→    return result;
   112→  }
   113→
   114→  /**
   115→   * Add an element to the layer (stores in graph)
   116→   */
   117→  addElement(element: Element): void {
   118→    // Ensure element has the correct layer
   119→    element.layer = this.name;
   120→    // Also set layer_id to maintain consistency with layer name
   121→    if (!element.layer_id || element.layer_id === "") {
   122→      element.layer_id = this.name;
   123→    }
   124→    const node = GraphModel.fromElement(element);
   125→
   126→    // Store references and relationships as node properties for preservation
   127→    if (element.references && element.references.length > 0) {
   128→      node.properties["__references__"] = element.references;
   129→    }
   130→    if (element.relationships && element.relationships.length > 0) {
   131→      node.properties["__relationships__"] = element.relationships;
   132→    }
   133→
   134→    // Add node to graph first
   135→    this.graph.addNode(node);
   136→
   137→    // Create graph edges from references for export compatibility
   138→    // Only create edges if both source and destination nodes exist
   139→    if (element.references && element.references.length > 0) {
   140→      for (const ref of element.references) {
   141→        if (this.graph.nodes.has(ref.source) && this.graph.nodes.has(ref.target)) {
   142→          this.graph.addEdge({
   143→            id: `${ref.source}-${ref.type}-${ref.target}`,
   144→            source: ref.source,
   145→            destination: ref.target,
   146→            predicate: ref.type,
   147→            properties: {},
   148→          });
   149→        }
   150→      }
   151→    }
   152→
   153→    // Create graph edges from relationships for export compatibility
   154→    // Only create edges if both source and destination nodes exist
   155→    if (element.relationships && element.relationships.length > 0) {
   156→      for (const rel of element.relationships) {
   157→        if (this.graph.nodes.has(rel.source) && this.graph.nodes.has(rel.target)) {
   158→          this.graph.addEdge({
   159→            id: `${rel.source}-${rel.predicate}-${rel.target}`,
   160→            source: rel.source,
   161→            destination: rel.target,
   162→            predicate: rel.predicate,
   163→            properties: {},
   164→          });
   165→        }
   166→      }
   167→    }
   168→
   169→    this.dirty = true;
   170→  }
   171→
   172→  /**
   173→   * Get an element by UUID from the graph.
   174→   * Only direct UUID lookup is supported; semantic ID lookup has been removed.
   175→   *
   176→   * @param id - UUID of the element to get
   177→   * @returns The element if found, undefined if not found
   178→   */
   179→  getElement(id: string): Element | undefined {
   180→    const node = this.graph.nodes.get(id);
   181→
   182→    if (!node || node.layer !== this.name) {
   183→      return undefined;
   184→    }
   185→
   186→    return new Element({
   187→      id: node.id,
   188→      spec_node_id: node.spec_node_id,
   189→      layer_id: node.layer_id,
   190→      type: node.type,
   191→      name: node.name,
   192→      description: node.description,
   193→      attributes: node.attributes,
   194→      source_reference: node.source_reference,
   195→      metadata: node.metadata,
   196→      layer: node.layer,
   197→      references: (node.properties["__references__"] ?? []) as Reference[],
   198→      relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   199→    });
   200→  }
   201→
   202→  /**
   203→   * Find an element by semantic ID (for testing/compatibility).
   204→   * This is a helper method for finding elements by semantic ID format:
   205→   * - Dot-separated: {layer}.{type}.{kebab-name}
   206→   * - Hyphen-separated legacy: {layer}-{type}-{kebab-name}
   207→   *
   208→   * @param semanticId - Semantic ID of the element to find
   209→   * @returns The element if found, undefined if not found
   210→   */
   211→  findBySemanticId(semanticId: string): Element | undefined {
   212→    const dotCount = (semanticId.match(/\./g) || []).length;
   213→    const isDotSeparated = dotCount >= 2;
   214→    const isHyphenSeparated = semanticId.includes("-") && semanticId.startsWith(this.name) && semanticId.length > this.name.length + 1;
   215→
   216→    if (!isDotSeparated && !isHyphenSeparated) {
   217→      return undefined;
   218→    }
   219→
   220→    // Search all nodes in the layer
   221→    for (const candidate of this.graph.nodes.values()) {
   222→      if (candidate.layer !== this.name) {
   223→        continue;
   224→      }
   225→
   226→      // Build semantic IDs from element name
   227→      const kebabName = candidate.name
   228→        .replace(/[\s_]+/g, "-")
   229→        .replace(/([a-z])([A-Z])/g, "$1-$2")
   230→        .toLowerCase()
   231→        .replace(/-+/g, "-")
   232→        .replace(/^-+|-+$/g, "");
   233→
   234→      const semanticIds = [
   235→        `${candidate.layer_id || this.name}.${candidate.type}.${kebabName}`,
   236→        `${candidate.layer_id || this.name}-${candidate.type}-${kebabName}`,
   237→      ];
   238→
   239→      if (semanticIds.includes(semanticId)) {
   240→        return new Element({
   241→          id: candidate.id,
   242→          spec_node_id: candidate.spec_node_id,
   243→          layer_id: candidate.layer_id,
   244→          type: candidate.type,
   245→          name: candidate.name,
   246→          description: candidate.description,
   247→          attributes: candidate.attributes,
   248→          source_reference: candidate.source_reference,
   249→          metadata: candidate.metadata,
   250→          layer: candidate.layer,
   251→          references: (candidate.properties["__references__"] ?? []) as Reference[],
   252→          relationships: (candidate.properties["__relationships__"] ?? []) as Relationship[],
   253→        });
   254→      }
   255→    }
   256→
   257→    return undefined;
   258→  }
   259→
   260→  /**
   261→   * Update an element in the graph
   262→   */
   263→  updateElement(element: Element): boolean {
   264→    const node = this.graph.nodes.get(element.id);
   265→    if (!node || node.layer !== this.name) {
   266→      return false;
   267→    }
   268→
   269→    // Prepare properties including references and relationships
   270→    // Start with existing node properties to preserve graph metadata fields like __references__ and __relationships__
   271→    const properties = { ...node.properties };
   272→
   273→    // Persist references and relationships as node properties
   274→    if (element.references && element.references.length > 0) {
   275→      properties["__references__"] = element.references;
   276→    } else {
   277→      delete properties["__references__"];
   278→    }
   279→
   280→    if (element.relationships && element.relationships.length > 0) {
   281→      properties["__relationships__"] = element.relationships;
   282→    } else {
   283→      delete properties["__relationships__"];
   284→    }
   285→
   286→    // Convert element to graph node and update in place, including spec-node fields
   287→    // so that source_reference and attributes changes aren't lost on the next save cycle
   288→    const updated = this.graph.updateNode(element.id, {
   289→      name: element.name,
   290→      description: element.description,
   291→      properties,
   292→      spec_node_id: element.spec_node_id || undefined,
   293→      layer_id: element.layer_id || undefined,
   294→      attributes: element.attributes,
   295→      source_reference: element.source_reference,
   296→      metadata: element.metadata,
   297→    });
   298→
   299→    if (updated) {
   300→      this.dirty = true;
   301→    }
   302→    return updated;
   303→  }
   304→
   305→  /**
   306→   * Delete an element by ID from the graph
   307→   *
   308→   * @param id - UUID of the element to delete
   309→   * @returns true if element was deleted, false if not found
   310→   */
   311→  deleteElement(id: string): boolean {
   312→    const node = this.graph.nodes.get(id);
   313→
   314→    if (!node || node.layer !== this.name) {
   315→      return false;
   316→    }
   317→
   318→    const result = this.graph.removeNode(node.id);
   319→    if (result) {
   320→      this.dirty = true;
   321→    }
   322→    return result;
   323→  }
   324→
   325→  /**
   326→   * List all elements in the layer from the graph
   327→   */
   328→  listElements(): Element[] {
   329→    const nodes = this.graph.getNodesByLayer(this.name);
   330→    return nodes.map(
   331→      (node) =>
   332→        new Element({
   333→          id: node.id,
   334→          spec_node_id: node.spec_node_id,
   335→          layer_id: node.layer_id,
   336→          type: node.type,
   337→          name: node.name,
   338→          description: node.description,
   339→          attributes: node.attributes,
   340→          source_reference: node.source_reference,
   341→          metadata: node.metadata,
   342→          layer: node.layer,
   343→          references: (node.properties["__references__"] ?? []) as Reference[],
   344→          relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   345→        })
   346→    );
   347→  }
   348→
   349→  /**
   350→   * Check if layer has unsaved changes
   351→   */
   352→  isDirty(): boolean {
   353→    return this.dirty;
   354→  }
   355→
   356→  /**
   357→   * Mark layer as clean (no unsaved changes)
   358→   */
   359→  markClean(): void {
   360→    this.dirty = false;
   361→  }
   362→
   363→  /**
   364→   * Serialize to JSON representation
   365→   */
   366→  toJSON(): LayerData {
   367→    const result: LayerData = {
   368→      elements: this.listElements().map((e) => e.toJSON()),
   369→    };
   370→
   371→    if (this.metadata) {
   372→      result.metadata = this.metadata;
   373→    }
   374→
   375→    return result;
   376→  }
   377→
   378→  /**
   379→   * Create Layer from JSON data
   380→   */
   381→  static fromJSON(name: string, data: LayerData, graph?: GraphModel): Layer {
   382→    const elements = data.elements.map(
   383→      (e) =>
   384→        new Element({
   385→          id: e.id,
   386→          spec_node_id: e.spec_node_id,
   387→          layer_id: e.layer_id,
   388→          type: e.type,
   389→          name: e.name,
   390→          description: e.description,
   391→          attributes: e.attributes,
   392→          source_reference: e.source_reference,
   393→          metadata: e.metadata,
   394→          references: e.references,
   395→          relationships: e.relationships,
   396→          layer: name,
   397→        })
   398→    );
   399→    const layer = new Layer(name, graph, elements);
   400→    layer.metadata = data.metadata;
   401→    return layer;
   402→  }
   403→}
