    10→import { validateSourceReferenceOptions, buildSourceReference } from "../utils/source-reference.js";
    11→import { startSpan, endSpan } from "../telemetry/index.js";
    12→
    13→declare const TELEMETRY_ENABLED: boolean | undefined;
    14→const isTelemetryEnabled = typeof TELEMETRY_ENABLED !== "undefined" ? TELEMETRY_ENABLED : false;
    15→
    16→export interface UpdateOptions {
    17→  name?: string;
    18→  description?: string;
    19→  attributes?: string;
    20→  sourceFile?: string;
    21→  sourceSymbol?: string;
    22→  sourceProvenance?: string;
    23→  sourceRepoRemote?: string;
    24→  sourceRepoCommit?: string;
    25→  clearSourceReference?: boolean;
    26→  verbose?: boolean;
    27→  debug?: boolean;
    28→}
    29→
    30→/**
    31→ * Validate update-specific source reference options
    32→ */
    33→function validateUpdateSourceReferenceOptions(options: UpdateOptions): void {
    34→  const hasSourceOptions =
    35→    options.sourceFile ||
    36→    options.sourceSymbol ||
    37→    options.sourceProvenance ||
    38→    options.sourceRepoRemote ||
    39→    options.sourceRepoCommit;
    40→
    41→  if (options.clearSourceReference && hasSourceOptions) {
    42→    throw new CLIError(
    43→      "Cannot use --clear-source-reference with other source reference options",
    44→      1,
    45→      ["Specify either --clear-source-reference or other source options, not both"]
    46→    );
    47→  }
    48→
    49→  // Use shared validation for source reference options if any are provided
    50→  if (hasSourceOptions) {
    51→    validateSourceReferenceOptions(options);
    52→  }
    53→}
    54→
    55→export async function updateCommand(id: string, options: UpdateOptions): Promise<void> {
    56→  const changedFields: string[] = [];
    57→  if (options.name) changedFields.push("name");
    58→  if (options.description) changedFields.push("description");
    59→  if (options.attributes) changedFields.push("attributes");
    60→  if (options.sourceFile || options.clearSourceReference) changedFields.push("sourceReference");
    61→
    62→  const span = isTelemetryEnabled
    63→    ? startSpan("element.update", {
    64→        "element.id": id,
    65→        "element.changed_fields": changedFields.join(","),
    66→      })
    67→    : null;
    68→
    69→  try {
    70→    // Validate source reference options
    71→    validateUpdateSourceReferenceOptions(options);
    72→
    73→    // Load model
    74→    const model = await Model.load();
    75→
    76→    // Find element
    77→    const layerName = await findElementLayer(model, id);
    78→    if (!layerName) {
    79→      throw new CLIError(`Element ${id} not found`, 1);
    80→    }
    81→
    82→    const layer = await model.getLayer(layerName);
    83→    if (!layer) {
    84→      throw new CLIError(`Layer ${layerName} not found`, 1);
    85→    }
    86→
    87→    const element = layer.getElement(id);
    88→    if (!element) {
    89→      throw new CLIError(`Element ${id} not found`, 1);
    90→    }
    91→
    92→    // Validate that at least one field is specified
    93→    const hasUpdates =
    94→      options.name ||
    95→      options.description !== undefined ||
    96→      options.attributes ||
    97→      options.sourceFile ||
    98→      options.clearSourceReference;
    99→
   100→    if (!hasUpdates) {
   101→      console.log(ansis.yellow("No fields specified for update"));
   102→      return;
   103→    }
   104→
   105→    // Single unified mutation handler for update
   106→    const handler = new MutationHandler(model, id, layerName);
   107→
   108→    // Execute update through unified path (handles staging and base model consistently)
   109→    // The mutator function applies all updates in a single pass with validated JSON parsing
   110→    await handler.executeUpdate(element, async (elem, after) => {
   111→      // Parse JSON once here in the mutator - shared by both staging and base paths
   112→      let parsedAttributes: Record<string, unknown> | undefined;
   113→      if (options.attributes) {
   114→        try {
   115→          parsedAttributes = JSON.parse(options.attributes);
   116→        } catch (e) {
   117→          throw new CLIError("Invalid JSON in --attributes", 1, [
   118→            "Ensure your JSON is valid and properly formatted",
   119→          ]);
   120→        }
   121→      }
   122→
   123→      // Apply updates to both element and after state
   124→      if (options.name) {
   125→        elem.name = options.name;
   126→        after.name = options.name;
   127→      }
   128→
   129→      if (options.description !== undefined) {
   130→        elem.description = options.description || undefined;
   131→        after.description = options.description || undefined;
   132→      }
   133→
   134→      if (parsedAttributes) {
   135→        elem.attributes = { ...elem.attributes, ...parsedAttributes };
   136→        after.attributes = {
   137→          ...(after.attributes as Record<string, unknown>),
   138→          ...parsedAttributes,
   139→        };
   140→      }
   141→
   142→      if (options.clearSourceReference) {
   143→        elem.setSourceReference(undefined);
   144→        after.sourceReference = undefined;
   145→      } else if (options.sourceFile) {
   146→        const newRef = buildSourceReference(options);
   147→        if (newRef) {
   148→          elem.setSourceReference(newRef);
   149→          after.sourceReference = newRef;
   150→        }
   151→      }
   152→
   153→      // Update element in layer graph to persist mutations
   154→      layer.updateElement(elem);
   155→    });
   156→
   157→    console.log(ansis.green(`✓ Updated element ${ansis.bold(id)}`));
   158→    if (options.verbose) {
   159→      console.log(ansis.dim(`  Layer: ${layerName}`));
   160→      if (options.name) {
   161→        console.log(ansis.dim(`  Name: ${options.name}`));
   162→      }
   163→      if (options.description) {
   164→        console.log(ansis.dim(`  Description: ${options.description}`));
   165→      }
   166→      if (options.sourceFile) {
   167→        console.log(ansis.dim(`  Source: ${options.sourceFile}`));
   168→      }
   169→      if (options.clearSourceReference) {
   170→        console.log(ansis.dim(`  Source: cleared`));
   171→      }
   172→    }
   173→  } catch (error) {
   174→    if (isTelemetryEnabled && span) {
   175→      (span as any).recordException(error as Error);
   176→      (span as any).setStatus({ code: 2, message: (error as Error).message });
   177→    }
   178→    handleError(error);
   179→  } finally {
   180→    if (isTelemetryEnabled) {
   181→      endSpan(span);
   182→    }
   183→  }
   184→}
