    19→/**
    20→ * Convert a PascalCase title to snake_case.
    21→ * Handles acronyms correctly: "UXApplication" → "ux_application", "OpenAPIDocument" → "open_api_document".
    22→ */
    23→function titleToSnakeCase(title: string): string {
    24→  return title
    25→    .replace(/([A-Z]+)([A-Z][a-z])/g, "$1_$2") // "APIDoc" → "API_Doc"
    26→    .replace(/([a-z\d])([A-Z])/g, "$1_$2")       // "appComponent" → "app_Component"
    27→    .toLowerCase();
    28→}
    29→
    30→/**
    31→ * Derive a snake_case file stem for a given element type.
    32→ * Uses the spec node title for accurate word boundaries (e.g., "InputSpacePartition" → "input_space_partition").
    33→ * Falls back to the raw type string when the title is unavailable.
    34→ */
    35→function typeToSnakeStem(specNodeId: string | undefined, type: string): string {
    36→  if (specNodeId) {
    37→    const nodeType = getNodeType(specNodeId as SpecNodeId);
    38→    if (nodeType?.title) {
    39→      return titleToSnakeCase(nodeType.title);
    40→    }
    41→  }
    42→  return type;
    43→}
