   246→  /**
   247→   * Add a layer to the model
   248→   */
   249→  addLayer(layer: Layer): void {
   250→    // If the layer has elements in its isolated graph, migrate them to the model's graph
   251→    if (layer.graph.getNodeCount() > 0) {
   252→      for (const node of layer.graph.nodes.values()) {
   253→        this.graph.addNode(node);
   254→      }
   255→      for (const edge of layer.graph.edges.values()) {
   256→        this.graph.addEdge(edge);
   257→      }
   258→    }
   259→    // Ensure layer uses the model's graph for future operations
   260→    layer.graph = this.graph;
   261→    this.layers.set(layer.name, layer);
   262→    this.loadedLayers.add(layer.name);
   263→  }
