   434→  /**
   435→   * Save the manifest to disk (documentation-robotics/model/manifest.yaml)
   436→   */
   437→  async saveManifest(): Promise<void> {
   438→    this.manifest.updateModified();
   439→    const yaml = await import("yaml");
   440→    const manifestPath = `${this.rootPath}/documentation-robotics/model/manifest.yaml`;
   441→
   442→    // Convert to YAML format
   443→    const yamlData: any = {
   444→      version: this.manifest.version,
   445→      schema: "documentation-robotics-v1",
   446→      cli_version: getCliVersion(),
   447→      spec_version: this.manifest.specVersion,
   448→      created: this.manifest.created,
   449→      updated: this.manifest.modified,
   450→      project: {
   451→        name: this.manifest.name,
   452→        description: this.manifest.description,
   453→        version: this.manifest.version,
   454→      },
   455→      documentation: ".dr/README.md",
   456→      layers: {},
   457→    };
   458→
   459→    // Generate layer structure from current model state
   460→    const layerOrder = [
   461→      "motivation",
   462→      "business",
   463→      "security",
   464→      "application",
   465→      "technology",
   466→      "api",
   467→      "data-model",
   468→      "data-store",
   469→      "ux",
   470→      "navigation",
   471→      "apm",
   472→      "testing",
   473→    ];
   474→
   475→    for (let i = 0; i < layerOrder.length; i++) {
   476→      const layerName = layerOrder[i];
   477→      const layer = this.layers.get(layerName);
   478→      const orderNum = String(i + 1).padStart(2, "0");
   479→
   480→      yamlData.layers[layerName] = {
   481→        order: i + 1,
   482→        name: layerName.charAt(0).toUpperCase() + layerName.slice(1).replace("-", " "),
   483→        path: `documentation-robotics/model/${orderNum}_${layerName}/`,
   484→        enabled: true,
   485→        ...(layer && { elements: this.getLayerElementCounts(layer) }),
   486→      };
   487→    }
   488→
   489→    if (this.manifest.changeset_history && this.manifest.changeset_history.length > 0) {
   490→      yamlData.changeset_history = this.manifest.changeset_history;
   491→    }
   492→
   493→    await ensureDir(`${this.rootPath}/documentation-robotics/model`);
   494→    await writeFile(manifestPath, yaml.stringify(yamlData));
   495→  }
