   505→  /**
   506→   * Load relationships from relationships.yaml
   507→   */
   508→  async loadRelationships(): Promise<void> {
   509→    const fs = await import("fs/promises");
   510→    const yaml = await import("yaml");
   511→    const relationshipsPath = `${this.rootPath}/documentation-robotics/model/relationships.yaml`;
   512→
   513→    try {
   514→      const yamlContent = await fs.readFile(relationshipsPath, "utf-8");
   515→      const data = yaml.parse(yamlContent);
   516→
   517→      if (Array.isArray(data)) {
   518→        this.relationships = Relationships.fromArray(data);
   519→        // Sync relationships to graph
   520→        for (let i = 0; i < data.length; i++) {
   521→          const rel = data[i];
   522→          const edge: GraphEdge = {
   523→            id: `rel-${i}-${crypto.randomBytes(4).toString("hex")}`,
   524→            source: rel.source,
   525→            destination: rel.target,
   526→            predicate: rel.predicate,
   527→            properties: rel.properties,
   528→            category: rel.category,
   529→          };
   530→          this.graph.addEdge(edge);
   531→        }
   532→      }
   533→    } catch (err) {
   534→      // If file doesn't exist, that's okay - start with empty relationships
   535→      if ((err as any).code !== "ENOENT") {
   536→        // But if it's a different error, we should know about it
   537→        if (process.env.DEBUG) {
   538→          console.debug(`Warning: Failed to load relationships.yaml: ${err}`);
   539→        }
   540→      }
   541→    }
   542→  }
