   544→  /**
   545→   * Save relationships to relationships.yaml
   546→   */
   547→  async saveRelationships(): Promise<void> {
   548→    const fs = await import("fs/promises");
   549→    const yaml = await import("yaml");
   550→    const relationshipsPath = `${this.rootPath}/documentation-robotics/model/relationships.yaml`;
   551→
   552→    await ensureDir(`${this.rootPath}/documentation-robotics/model`);
   553→
   554→    const data = this.relationships.toArray();
   555→
   556→    // Add header comment with timestamp to ensure file always changes
   557→    const timestamp = new Date().toISOString();
   558→    const header = `# Intra-layer relationships
   559→# Format: source_id -> predicate -> target_id
   560→# Last updated: ${timestamp}
   561→
   562→`;
   563→    const yamlContent = header + yaml.stringify(data);
   564→
   565→    await fs.writeFile(relationshipsPath, yamlContent, "utf-8");
   566→    this.relationships.markClean();
