   627→  /**
   628→   * Load a model from disk
   629→   *
   630→   * Expected structure:
   631→   * <project-root>/
   632→   * └── documentation_robotics/
   633→   *     └── model/
   634→   *         └── manifest.yaml
   635→   *
   636→   * @param startPath - Starting path for project search (defaults to process.cwd())
   637→   * @param options - Model loading options
   638→   * @returns Loaded Model instance
   639→   */
   640→  static async load(startPath?: string, options: ModelOptions = {}): Promise<Model> {
   641→    const span = isTelemetryEnabled
   642→      ? startSpan("model.load", {
   643→          "model.path": startPath || process.cwd(),
   644→          "model.type": "dr",
   645→        })
   646→      : null;
   647→
   648→    try {
   649→      // Resolve project root and manifest path
   650→      const { projectRoot, manifestPath } = await Model.resolveModelPaths(startPath);
   651→
   652→      const yaml = await import("yaml");
   653→
   654→      // Load manifest from resolved path
   655→      const yamlContent = await fs.readFile(manifestPath, "utf-8");
   656→      const manifestYaml = yaml.parse(yamlContent);
   657→
   658→      // Convert manifest to internal format
   659→      const manifestData: any = {
   660→        name: manifestYaml.project?.name || "Unnamed Model",
   661→        description: manifestYaml.project?.description || "",
   662→        version: manifestYaml.project?.version || manifestYaml.version || "0.1.0",
   663→        specVersion: manifestYaml.spec_version || "0.6.0",
   664→        created: manifestYaml.created || new Date().toISOString(),
   665→        modified: manifestYaml.updated || new Date().toISOString(),
   666→      };
   667→      const manifest = new Manifest(manifestData);
   668→      const model = new Model(projectRoot, manifest, options);
   669→
   670→      // Load all available layers if lazyLoad is false
   671→      if (!options.lazyLoad) {
   672→        try {
   673→          // If manifest has layer definitions, use those
   674→          if (manifestYaml.layers) {
   675→            for (const layerName of Object.keys(manifestYaml.layers)) {
   676→              const layerConfig = manifestYaml.layers[layerName];
   677→              if (layerConfig.enabled !== false) {
   678→                await model.loadLayer(layerName);
   679→              }
   680→            }
   681→          } else {
   682→            // Otherwise scan for layer directories
   683→            const modelDir = manifestPath.replace("/manifest.yaml", "");
   684→            const entries = await fs.readdir(modelDir, { withFileTypes: true });
   685→
   686→            for (const entry of entries) {
   687→              if (entry.isDirectory() && entry.name.match(/^\d{2}_/)) {
   688→                const layerName = entry.name.replace(/^\d{2}_/, "");
   689→                await model.loadLayer(layerName);
   690→              }
   691→            }
   692→          }
   693→        } catch (e) {
   694→          // Check if this is a "directory not found" error (expected case)
   695→          const isNotFoundError = (e as any)?.code === "ENOENT";
   696→          if (!isNotFoundError) {
   697→            // Re-throw non-ENOENT errors: permission errors, YAML parsing failures, I/O errors, etc.
   698→            throw new Error(
   699→              `Failed to load layers: ${e instanceof Error ? e.message : String(e)}`
   700→            );
   701→          }
   702→          // ENOENT is expected if layer directory doesn't exist yet, so just continue
   703→        }
   704→      }
   705→
   706→      // Load relationships from relationships.yaml
   707→      await model.loadRelationships();
   708→
   709→      // Count total entities across all layers
   710→      let entityCount = 0;
   711→      for (const layer of model.layers.values()) {
   712→        entityCount += layer.elements.size;
   713→      }
   714→
   715→      if (isTelemetryEnabled && span) {
   716→        span.setAttribute("model.entity_count", entityCount);
   717→        span.setAttribute("model.layer_count", model.layers.size);
   718→      }
   719→
   720→      return model;
   721→    } finally {
   722→      if (isTelemetryEnabled) {
   723→        endSpan(span);
   724→      }
   725→    }
   726→  }
