   814→  /**
   815→   * Create a backup of the current model state
   816→   * Used for rollback support in migration operations
   817→   *
   818→   * @param label Descriptive label for the backup (e.g., "pre-migration")
   819→   * @returns Path to the backup directory
   820→   */
   821→  async createBackup(label: string): Promise<string> {
   822→    const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
   823→    const backupDir = path.join(this.rootPath, ".dr-backups", `${label}-${timestamp}`);
   824→
   825→    // Create backup directory
   826→    await ensureDir(backupDir);
