    84→      return this.cachedElements;
    85→    }
    86→
    87→    // Rebuild cache
    88→    const result = new Map<string, Element>();
    89→    const nodes = this.graph.getNodesByLayer(this.name);
    90→
    91→    for (const node of nodes) {
    92→      const element = new Element({
    93→        id: node.id,
    94→        spec_node_id: node.spec_node_id,
    95→        layer_id: node.layer_id,
    96→        type: node.type,
    97→        name: node.name,
    98→        description: node.description,
    99→        attributes: node.attributes,
   100→        source_reference: node.source_reference,
   101→        metadata: node.metadata,
   102→        layer: node.layer,
   103→        references: (node.properties["__references__"] ?? []) as Reference[],
   104→        relationships: (node.properties["__relationships__"] ?? []) as Relationship[],
   105→      });
   106→      result.set(node.id, element);
   107→    }
