+ * @param semanticId - Semantic ID of the element to find
+ * @returns The element if found, undefined if not found
+ */
+export function findElementBySemanticId(
+  layer: Layer,
+  semanticId: string
+): Element | undefined {
+  const dotCount = (semanticId.match(/\./g) || []).length;
