+  const isHyphenSeparated =
+    semanticId.includes("-") &&
+    semanticId.startsWith(layer.name) &&
+    semanticId.length > layer.name.length + 1;
+
+  if (!isDotSeparated && !isHyphenSeparated) {
+    return undefined;
+  }
+
+  // Search all nodes in the layer
+  for (const candidate of layer.nodes) {
+    // Build semantic IDs from element name
+    const kebabName = candidate.name
+      .replace(/[\s_]+/g, "-")
+      .replace(/([a-z])([A-Z])/g, "$1-$2")
+      .toLowerCase()
+      .replace(/-+/g, "-")
+      .replace(/^-+|-+$/g, "");
